using System;
using System.IO;

public class ConfigService
{
    public string RaizDoProjeto { get; private set; }

    public ConfigService()
    {
        // Obtém o diretório do executável e sobe 3 níveis (bin/Debug/net8.0) 
        // para chegar na raiz do projeto durante o desenvolvimento.
        // Em produção, isso pode ser configurado de outra forma.
        string baseDir = AppDomain.CurrentDomain.BaseDirectory;
        RaizDoProjeto = Path.GetFullPath(Path.Combine(baseDir, "..", "..", ".."));
    }

    public static class PathResolver
    {
        public static string ObterCaminhoRaiz()
        {
            // Obtém o diretório do executável (bin/Debug/net10.0)
            string baseDir = AppDomain.CurrentDomain.BaseDirectory;

            // Se estivermos em ambiente de desenvolvimento, subimos 3 níveis 
            // para sair de net10.0 -> Debug -> bin e chegar na raiz do projeto
            string raizProvavel = Path.GetFullPath(Path.Combine(baseDir, "..", "..", ".."));

            // Verifica se a pasta Data existe na raiz; se não, usa o diretório base
            if (Directory.Exists(Path.Combine(raizProvavel, "Data")))
            {
                return raizProvavel;
            }

            return baseDir;
        }
    }
}

