using ScottPlot;
using Scriptome.Nucleo.Modelos;
using Scriptome.Nucleo.Modelos.Analise;
using System;
using System.IO;
using System.Linq;

namespace Scriptome.Infrastructure
{
    public class ScriptomeVisualizer
    {
        public void GerarGraficos(EstatisticasRoteiro stats, string pathBase)
        {
            if (stats == null || string.IsNullOrEmpty(pathBase)) return;

            // Garante que a pasta existe antes de tentar salvar
            if (!Directory.Exists(pathBase)) Directory.CreateDirectory(pathBase);

            GerarArcoDramatico(stats, pathBase);
            GerarOctogonoDNA(stats, pathBase);
        }

        private void GerarArcoDramatico(EstatisticasRoteiro stats, string pathBase)
        {
            try
            {
                var plot = new ScottPlot.Plot();

                double[] ids = stats.Cenas.Select(c => (double)c.Id).ToArray();
                double[] pacing = stats.Cenas.Select(c => c.PacingScore).ToArray();
                double[] dramatismo = stats.Cenas.Select(c => c.DramatismoTotal * 10).ToArray();

                var sig1 = plot.Add.Scatter(ids, pacing);
                sig1.LegendText = "Pacing (Ritmo)";
                sig1.LineColor = Colors.Cyan;
                sig1.LineWidth = 3;

                var sig2 = plot.Add.Scatter(ids, dramatismo);
                sig2.LegendText = "Dramatismo (Conflito)";
                sig2.LineColor = Colors.DeepPink;
                sig2.LineWidth = 3;

                // Estética Noir
                plot.Title($"Arco Narrativo: {stats.NomeTexto}");
                plot.Axes.Color(Colors.White);
                plot.FigureBackground.Color = Colors.Black;
                plot.DataBackground.Color = Colors.Black;

                string fullPath = Path.Combine(pathBase, "Arco_Dramatico.png");
                plot.SavePng(fullPath, 1200, 600);
                Console.WriteLine($"   + [VISUALIZER] Arco salvo: {fullPath}");
            }
            catch (Exception ex) { Console.WriteLine($"   ! [ERRO ARCO] {ex.Message}"); }
        }

        private void GerarOctogonoDNA(EstatisticasRoteiro stats, string pathBase)
        {
            try
            {
                var plot = new ScottPlot.Plot();

                var labels = stats.DnaGlobal.Keys.ToArray();
                var values = stats.DnaGlobal.Values.ToArray();

                if (values.Length == 0) return;

                plot.Add.Radar(values);

                plot.Title("DNA Narrativo (Octógono)");

                // Fundo branco
                plot.FigureBackground.Color = ScottPlot.Colors.White;
                plot.DataBackground.Color = ScottPlot.Colors.White;
                plot.Axes.Color(ScottPlot.Colors.Black);

                // =========================
                // Labels e valores do radar
                // =========================
                double raioLabel = 8.5;
                double raioValor = 7.5;

                int n = labels.Length;

                for (int i = 0; i < n; i++)
                {
                    double angulo = (Math.PI * 2 * i / n) - Math.PI / 2;

                    double lx = Math.Cos(angulo) * raioLabel;
                    double ly = Math.Sin(angulo) * raioLabel;

                    double vx = Math.Cos(angulo) * raioValor;
                    double vy = Math.Sin(angulo) * raioValor;

                    plot.Add.Text(labels[i], lx, ly);
                    plot.Add.Text(values[i].ToString("0.0"), vx, vy);
                }

                plot.Axes.SetLimits(-9, 9, -9, 9);

                string fullPath = Path.Combine(pathBase, "DNA_Octogon.png");
                plot.SavePng(fullPath, 800, 800);

                Console.WriteLine($"   + [VISUALIZER] Octógono salvo: {fullPath}");
            }
            catch (Exception ex)
            {
                Console.WriteLine($"   ! [ERRO DNA] {ex.Message}");
            }
        }





    }
}

using System.Text;
using System.Text.RegularExpressions;

namespace Scriptome.Infrastructure
{
    public static class ZumbiScanner
    {
        public static void Escanear(string root)
        {
            Console.WriteLine("\n🧟 Iniciando varredura arquitetural...\n");

            var arquivos = Directory.GetFiles(root, "*.cs", SearchOption.AllDirectories)
                .Where(f => !f.Contains("\\bin\\") && !f.Contains("\\obj\\"))
                .ToList();

            var tipos = new Dictionary<string, ClasseInfo>();

            var decl = new Regex(@"\b(class|interface|record)\s+([A-Za-z0-9_]+)");

            // Descobrir classes
            foreach (var file in arquivos)
            {
                foreach (var line in File.ReadAllLines(file))
                {
                    var m = decl.Match(line);
                    if (m.Success)
                    {
                        var nome = m.Groups[2].Value;

                        if (!tipos.ContainsKey(nome))
                        {
                            tipos[nome] = new ClasseInfo
                            {
                                Nome = nome,
                                Arquivo = Path.GetFileName(file),
                                Namespace = InferirNamespace(file)
                            };
                        }
                    }
                }
            }

            // Descobrir usos
            foreach (var file in arquivos)
            {
                var content = File.ReadAllText(file);
                var fileName = Path.GetFileName(file);

                foreach (var tipo in tipos.Values)
                {
                    var matches = Regex.Matches(content, $@"\b{tipo.Nome}\b");

                    int count = matches.Count;

                    if (tipo.Arquivo == fileName)
                        count--;

                    if (count > 0)
                    {
                        tipo.TotalUsos += count;
                        tipo.ReferenciadoPor.Add(fileName);
                    }
                }
            }

            ClassificarArquitetura(tipos.Values);

            GerarCsv(root, tipos.Values);

            Console.WriteLine("\n🧟 Varredura finalizada.");
        }

        static void ClassificarArquitetura(IEnumerable<ClasseInfo> tipos)
        {
            foreach (var t in tipos)
            {
                if (t.Nome == "Program")
                {
                    t.Camada = "Infra";
                    t.Status = "Infra essencial";
                    t.CandidatoRemocao = "NÃO";
                    continue;
                }

                if (t.Nome.StartsWith("Aba"))
                {
                    t.Camada = "UI";
                    t.Status = "UI";
                    t.CandidatoRemocao = "NÃO";
                    continue;
                }

                if (t.Namespace.Contains("Nucleo") ||
                    t.Namespace.Contains("Limbic"))
                {
                    t.Camada = "Core";
                    t.Status = "Core";
                    t.CandidatoRemocao = "NÃO";
                    continue;
                }

                if (t.TotalUsos == 0)
                {
                    t.Status = "Morto Absoluto";
                    t.CandidatoRemocao = "SIM";
                    continue;
                }

                if (t.ReferenciadoPor.Any(f =>
                    f.Contains("Adaptador") ||
                    f.Contains("MotorDeIdentidade")))
                {
                    t.Status = "Legado";
                    t.CandidatoRemocao = "Provável";
                    continue;
                }

                t.Status = "Ativo";
                t.CandidatoRemocao = "NÃO";
            }
        }

        static void GerarCsv(string root, IEnumerable<ClasseInfo> tipos)
        {
            var path = Path.Combine(root, "ZumbiReport.csv");

            using var writer = new StreamWriter(path, false, new UTF8Encoding(true));

            writer.WriteLine("Classe;Arquivo;Namespace;TotalUsos;Status;CandidatoRemocao;ReferenciadoPor");

            foreach (var t in tipos.OrderBy(x => x.TotalUsos))
            {
                writer.WriteLine($"{t.Nome};{t.Arquivo};{t.Namespace};{t.TotalUsos};{t.Status};{t.CandidatoRemocao};\"{string.Join(",", t.ReferenciadoPor)}\"");
            }

            Console.WriteLine($"📄 CSV salvo em: {path}");
        }

        static string InferirNamespace(string path)
        {
            var parts = path.Split("\\Scriptome\\");
            if (parts.Length < 2) return "Desconhecido";
            return parts[1].Replace("\\", ".").Replace(".cs", "");
        }

        class ClasseInfo
        {
            public string Nome { get; set; }
            public string Arquivo { get; set; }
            public string Namespace { get; set; }
            public int TotalUsos { get; set; } = 0;
            public string Camada { get; set; }
            public string Status { get; set; }
            public string CandidatoRemocao { get; set; }
            public HashSet<string> ReferenciadoPor { get; set; } = new();
        }
    }
}

