namespace Scriptome.Fingerprint.Modelos
{
    /// <summary>
    /// Representa a posição do personagem no espaço Etograma Cartesiano.
    /// X → Egoísmo × Altruísmo
    /// Y → Impulso (Id) × Norma (Superego)
    /// Z → Concreto × Abstrato
    /// </summary>
    /// 
    public struct VetorEtograma3D
    {
        public double EgoismoAltruismo;
        public double ImpulsoNorma;
        public double ConcretoAbstrato;

        public double Distancia(VetorEtograma3D outro)
        {
            return System.Math.Sqrt(
                System.Math.Pow(EgoismoAltruismo - outro.EgoismoAltruismo, 2) +
                System.Math.Pow(ImpulsoNorma - outro.ImpulsoNorma, 2) +
                System.Math.Pow(ConcretoAbstrato - outro.ConcretoAbstrato, 2)
            );
        }
    }
}

