namespace Scriptome.Fingerprint.MotoresEtograma
{
    public class ExtratorEtogramaDeriva6 : IExtratorEtograma
    {
        public VetorEtograma3D Extrair(PerfilPersonagem p)
        {
            // ==============================
            // EIXO X — Egoísmo × Altruísmo
            // ==============================
            double altruismo =
                (p.ScoreAfeto * 0.7) +
                (p.KarmaMoral * 0.3);

            double egoismo =
                (p.ScoreEgo * 0.5) +
                (p.ScoreDominancia * 0.5);

            double eixoX = altruismo - egoismo;

            // ==============================
            // EIXO Y — Id × Superego
            // ==============================
            double id =
                (p.ScoreVolicao +
                 p.ScoreSensorium +
                 p.ScoreDominancia) / 3.0;

            double superego =
                (p.ScoreRacionalidade +
                 p.ScoreErudicao +
                 p.KarmaOrdem) / 3.0;

            double eixoY = id - superego;

            // ==============================
            // EIXO Z — Concreto × Abstrato
            // ==============================
            double abstrato =
                (p.ScoreRacionalidade +
                 p.ScoreErudicao) / 2.0;

            double concreto = p.ScoreSensorium;

            double eixoZ = abstrato - concreto;

            // ==============================
            // NORMALIZAÇÃO (embedding-like)
            // ==============================
            return new VetorEtograma3D
            {
                EgoismoAltruismo = Normalizar(eixoX),
                ImpulsoNorma = Normalizar(eixoY),
                ConcretoAbstrato = Normalizar(eixoZ)
            };
        }

        private double Normalizar(double v)
        {
            return Math.Tanh(v / 3.0);
        }
    }
}

