public class MotorEtogramaCartesiano3D : IMotorEtogramaCartesiano
{
    private readonly IExtratorEtograma _extrator;
    private readonly ClassificadorEtogramaCartesiano _classificador;

    public string Nome => "Etograma Cartesiano 3D";

    public MotorEtogramaCartesiano3D(
        IExtratorEtograma extrator,
        ClassificadorEtogramaCartesiano classificador)
    {
        _extrator = extrator;
        _classificador = classificador;
    }

    public Etograma GerarEtograma(PerfilPersonagem p)
    {
        if (p.Etograma == null)
            p.Etograma = new Etograma();

        var vetor = _extrator.Extrair(p);
        p.VetorEtograma = vetor;

        p.Etograma.ArquetipoNarrativoFinal =
            _classificador.Inferir(vetor);

        p.Etograma.Processado = true;

        return p.Etograma;
    }
}

