namespace Scriptome.Fingerprint.MotoresEtograma
{
    /// <summary>
    /// MOTOR ETOGRAMA V2
    ///
    /// Pipeline sequencial dependente.
    /// Cada classificador recebe o estado acumulado.
    /// Produz ResultadoEtograma imutável.
    /// </summary>
    public sealed class MotorEtogramaV2
    {
        private readonly IList<IClassificadorEtogramaV2> _classificadores;

        public MotorEtogramaV2(
            IEnumerable<IClassificadorEtogramaV2> classificadores)
        {
            _classificadores = classificadores
                .ToList();
        }

        public ResultadoEtograma Gerar(
            PerfilPersonagem personagem)
        {
            if (personagem == null)
                throw new ArgumentNullException(nameof(personagem));

            var acumulado = new ParcialEtograma();

            foreach (var classificador in _classificadores)
            {
                var parcial =
                    classificador.Executar(
                        personagem,
                        acumulado);

                acumulado = Mesclar(acumulado, parcial);
            }

            return Consolidar(acumulado);
        }

        // ==========================================
        // MESCLAGEM DE PARCIAIS
        // ==========================================

        private ParcialEtograma Mesclar(
            ParcialEtograma atual,
            ParcialEtograma novo)
        {
            return atual with
            {
                ArquetipoNarrativoFinal =
                    novo.ArquetipoNarrativoFinal ?? atual.ArquetipoNarrativoFinal,

                ArquetipoJung =
                    novo.ArquetipoJung ?? atual.ArquetipoJung,

                IntensidadeImaginario =
                    novo.IntensidadeImaginario ?? atual.IntensidadeImaginario,

                IntensidadeSimbolico =
                    novo.IntensidadeSimbolico ?? atual.IntensidadeSimbolico,

                IntensidadeReal =
                    novo.IntensidadeReal ?? atual.IntensidadeReal,

                ScoreImaginario =
                    novo.ScoreImaginario ?? atual.ScoreImaginario,

                ScoreSimbolico =
                    novo.ScoreSimbolico ?? atual.ScoreSimbolico,

                ScoreReal =
                    novo.ScoreReal ?? atual.ScoreReal,

                RegistroDominante =
                    novo.RegistroDominante ?? atual.RegistroDominante,

                EstruturaPsiquica =
                    novo.EstruturaPsiquica ?? atual.EstruturaPsiquica,

                IntensidadeDiscursiva =
                    novo.IntensidadeDiscursiva ?? atual.IntensidadeDiscursiva,

                ClassificacaoIntensidade =
                    novo.ClassificacaoIntensidade ?? atual.ClassificacaoIntensidade,

                Termodinamica =
                    novo.Termodinamica ?? atual.Termodinamica,

                NivelCrueldade =
                    novo.NivelCrueldade ?? atual.NivelCrueldade,

                NivelManipulacao =
                    novo.NivelManipulacao ?? atual.NivelManipulacao,

                NivelErotizacao =
                    novo.NivelErotizacao ?? atual.NivelErotizacao,

                IndicePerversidade =
                    novo.IndicePerversidade ?? atual.IndicePerversidade,

                ClassificacaoPerversidade =
                    novo.ClassificacaoPerversidade ?? atual.ClassificacaoPerversidade,

                TipoMbti =
                    novo.TipoMbti ?? atual.TipoMbti,

                PerfilHibrido =
                    novo.PerfilHibrido ?? atual.PerfilHibrido
            };
        }

        // ==========================================
        // CONSOLIDAÇÃO FINAL
        // ==========================================

        private ResultadoEtograma Consolidar(
            ParcialEtograma p)
        {
            var arq =
                p.ArquetipoNarrativoFinal ??
                ArquetipoNarrativo.Indefinido;

            return new ResultadoEtograma(
                ArquetipoNarrativoFinal: arq,
                ArquetipoJung: p.ArquetipoJung ?? "Indefinido",
                CategoriaNarrativa:
                    BibliotecaArquetipos.ObterCategoria(arq),

                IntensidadeImaginario: p.IntensidadeImaginario ?? 0,
                IntensidadeSimbolico: p.IntensidadeSimbolico ?? 0,
                IntensidadeReal: p.IntensidadeReal ?? 0,

                ScoreImaginario: p.ScoreImaginario ?? 0,
                ScoreSimbolico: p.ScoreSimbolico ?? 0,
                ScoreReal: p.ScoreReal ?? 0,

                RegistroDominante: p.RegistroDominante ?? "Indefinido",
                EstruturaPsiquica: p.EstruturaPsiquica ?? "Indefinida",

                IntensidadeDiscursiva: p.IntensidadeDiscursiva ?? 0,
                ClassificacaoIntensidade: p.ClassificacaoIntensidade ?? "Indefinida",
                Termodinamica: p.Termodinamica ?? "Neutro",

                NivelCrueldade: p.NivelCrueldade ?? 0,
                NivelManipulacao: p.NivelManipulacao ?? 0,
                NivelErotizacao: p.NivelErotizacao ?? 0,
                IndicePerversidade: p.IndicePerversidade ?? 0,
                ClassificacaoPerversidade:
                    p.ClassificacaoPerversidade ?? "Indefinida",

                TipoMbti: p.TipoMbti ?? "XXXX",
                PerfilHibrido: p.PerfilHibrido ?? "Indefinido"
            );
        }
    }
}

using Scriptome.Nucleo.Modelos.Fenotipo;
using Scriptome.Nucleo.Modelos.Analise;
using System;

namespace Scriptome.Nucleo.Motores
{
    /// <summary>
    /// MOTOR VETORIAL V2 (PURO).
    ///
    /// Calcula posição geométrica no espaço etogramático 3D.
    /// Não classifica.
    /// Não muta objetos.
    /// Não depende de legado.
    /// </summary>
    public class MotorVetorialV2
    {
        public ExpressaoVetorial Construir(ResultadoBaseLinguistico b)
        {
            // ==============================
            // EIXO X — Egoísmo × Altruísmo
            // ==============================
            double altruismo =
                (b.ScoreAfeto * 0.7);

            double egoismo =
                (b.ScoreEgo * 0.5) +
                (b.ScoreDominancia * 0.5);

            double eixoX = altruismo - egoismo;

            // ==============================
            // EIXO Y — Impulso × Norma
            // ==============================
            double impulso =
                (b.ScoreVolicao +
                 b.ScoreSensorium +
                 b.ScoreDominancia) / 3.0;

            double norma =
                (b.ScoreRacionalidade +
                 b.ScoreErudicao) / 2.0;

            double eixoY = impulso - norma;

            // ==============================
            // EIXO Z — Concreto × Abstrato
            // ==============================
            double abstrato =
                (b.ScoreRacionalidade +
                 b.ScoreErudicao) / 2.0;

            double concreto =
                b.ScoreSensorium;

            double eixoZ = abstrato - concreto;

            return new ExpressaoVetorial(
                EgoismoAltruismo: Normalizar(eixoX),
                ImpulsoNorma: Normalizar(eixoY),
                ConcretoAbstrato: Normalizar(eixoZ)
            );
        }

        private double Normalizar(double v)
        {
            return Math.Tanh(v / 3.0);
        }
    }
}

using System;
using System.Collections.Generic;
using System.Text;

namespace Scriptome.Fingerprint.MotoresInterpretativos
{
    public sealed record ExpressaoIntencional(
        double Cognitiva,
        double Motora,
        double Emocional
    );
}

using Scriptome.Fingerprint.MotoresInterpretativos;
using Scriptome.Fingerprint.Interfaces;
using Scriptome.Nucleo.Modelos.Analise;

public sealed class MotorIntencionalV1 : IMotorIntencional
{
    public ExpressaoIntencional Calcular(PerfilPersonagem p)
    {
        var cognitiva =
            Math.Round((p.ScoreRacionalidade * 0.6) +
                       (p.ScoreErudicao * 0.4), 1);

        var motora =
            Math.Round((p.ScoreVolicao * 0.7) +
                       (p.ScoreDominancia * 0.3), 1);

        var emocional =
            Math.Round(p.ScoreAfeto, 1);

        return new ExpressaoIntencional(
            cognitiva,
            motora,
            emocional
        );
    }
}

using System.Text.Json;
using Scriptome.Nucleo.Modelos;
using System.IO;
using System.Linq;

namespace Scriptome.Infrastructure.Baseline
{
    /// <summary>
    /// Snapshot congelado do ELENCO LEGADO.
    /// Deve ser executado antes da migração para V2.
    /// </summary>
    public static class ExportadorBaselineElencoLegacyJson
    {
        public static void Exportar(EstatisticasRoteiro dados, string caminhoArquivo)
        {
            Directory.CreateDirectory(Path.GetDirectoryName(caminhoArquivo)!);

            var elenco = dados.AnalisePersonagens?
                .OrderByDescending(p => p.ScoreReal)
                .Select(p => new
                {
                    // =============================
                    // IDENTIDADE
                    // =============================
                    p.Nome,
                    p.QuantidadeFalas,

                    // =============================
                    // MORAL / DRAMÁTICO
                    // =============================
                    p.AlinhamentoMoral,
                    p.KarmaMoral,
                    Intensidade = $"{p.DramatismoMedio:F1} ({p.ArquetipoTermico})",

                    // =============================
                    // SCRIPTOME LEGADO
                    // =============================
                    ArquetipoScriptome = p.Etograma.ArquetipoNarrativoFinal.ToString(),

                    // =============================
                    // JUNG
                    // =============================
                    p.ArquetipoJung,

                    // =============================
                    // LACAN (RSI)
                    // =============================
                    Lacan = new
                    {
                        p.RegistroDominante,
                        p.ScoreReal,
                        p.ScoreSimbolico,
                        p.ScoreImaginario
                    },

                    p.EstruturaPsiquica,

                    // =============================
                    // PSICODINÂMICA
                    // =============================
                    p.IndicePerversidade,
                    p.ClassificacaoPerversidade,
                    p.NivelCrueldade,
                    p.NivelManipulacao,
                    p.NivelErotizacao,

                    // =============================
                    // MBTI (está dentro do Etograma)
                    // =============================
                    TipoMbti = p.Etograma.TipoMbti,

                    // =============================
                    // DERIVA (LEGADO)
                    // =============================
                    DERIVA = new
                    {
                        p.ScoreDominancia,
                        p.ScoreEgo,
                        p.ScoreRacionalidade,
                        p.ScoreIronia,
                        p.ScoreVolicao,
                        p.ScoreAfeto,
                        p.ScoreErudicao,
                        p.ScoreSensorium
                    },

                    // =============================
                    // ETOGRAMA 3D (Vetorial)
                    // =============================
                    ETOG = new
                    {
                        p.VetorEtograma.EgoismoAltruismo,
                        p.VetorEtograma.ImpulsoNorma,
                        p.VetorEtograma.ConcretoAbstrato
                    }
                });

            var json = JsonSerializer.Serialize(
                elenco,
                new JsonSerializerOptions
                {
                    WriteIndented = true
                });

            File.WriteAllText(caminhoArquivo, json);
        }
    }
}

using System;
using System.IO;
using System.Text.Json;

namespace Scriptome.Infrastructure.Baseline
{
    /// <summary>
    /// Exportador de Golden Master.
    /// 
    /// - Serializa qualquer objeto determinístico.
    /// - Não pertence ao domínio.
    /// - Preparado para futura migração para testes automatizados.
    /// </summary>
    public static class ExportadorBaselineEtograma
    {
        private static readonly JsonSerializerOptions _opcoes =
            new JsonSerializerOptions
            {
                WriteIndented = true,
                PropertyNamingPolicy = null
            };

        public static void Exportar<T>(
            T objeto,
            string caminhoArquivo)
        {
            if (objeto == null)
                throw new ArgumentNullException(nameof(objeto));

            var json = JsonSerializer.Serialize(objeto, _opcoes);

            var pasta = Path.GetDirectoryName(caminhoArquivo);
            if (!Directory.Exists(pasta))
                Directory.CreateDirectory(pasta!);

            File.WriteAllText(caminhoArquivo, json);
        }
    }
}

using System.IO;
using System.Text.Json;

namespace Scriptome.Infrastructure.Baseline
{
    /// <summary>
    /// Responsável por carregar baseline previamente congelado.
    /// 
    /// Futuramente será usado por testes automatizados.
    /// </summary>
    public static class LeitorBaseline
    {
        public static T Carregar<T>(string caminhoArquivo)
        {
            if (!File.Exists(caminhoArquivo))
                throw new FileNotFoundException(
                    "Baseline não encontrado.",
                    caminhoArquivo);

            var json = File.ReadAllText(caminhoArquivo);

            return JsonSerializer.Deserialize<T>(json)
                ?? throw new InvalidDataException(
                    "Falha ao desserializar baseline.");
        }
    }
}

using ClosedXML.Excel;
using Scriptome.Exportacao.Excel.Abas;
using Scriptome.Infrastructure.Exportacao;
using Scriptome.Infrastructure.Interfaces;
