using System.Linq;

namespace Scriptome.Exportacao
{
    public class ExportadorExcelModular : IExportadorScriptome
    {
        public string Nome => "Excel Modular v3.4 (With Visualizer Sync)";

        private readonly List<IAbaExcel> _abas;

        public ExportadorExcelModular()
        {
            _abas = new List<IAbaExcel>
            {
                new AbaDashboard(),
                new AbaBeatSheet(),
                new AbaAnaliseDeCenas(),
                new AbaElenco(),
                new AbaMatrizSocial(),
                new AbaTaxonomia()
            };
        }

        public void Exportar(EstatisticasRoteiro dados, string diretorioDestino)
        {
            // 1. GERAÇÃO DE GRÁFICOS (A Conexão Perdida)
            // Chamamos o Visualizer primeiro para que as imagens existam no disco
            try
            {
                Console.WriteLine("[VISUALIZER] Gerando gráficos de DNA e Octógono...");
                // Nota: Assumindo que ScriptomeVisualizer está no namespace Scriptome.Infrastructure ou similar
                var visualizador = new Scriptome.Infrastructure.ScriptomeVisualizer();
                visualizador.GerarGraficos(dados, diretorioDestino);
            }
            catch (Exception ex)
            {
                Console.ForegroundColor = ConsoleColor.Yellow;
                Console.WriteLine($"[AVISO] Visualizer não gerou imagens: {ex.Message}");
                Console.ResetColor();
            }

            // 2. PREPARAÇÃO DO EXCEL
            string timestamp = DateTime.Now.ToString("yyyyMMdd_HHmm");
            string nomeArquivo = $"Analise_{dados.NomeTexto ?? "Roteiro"}_{timestamp}.xlsx";
            string caminhoCompleto = Path.Combine(diretorioDestino, nomeArquivo);

            try
            {
                using (var workbook = new XLWorkbook())
                {
                    workbook.Properties.Author = "Scriptome AI";
                    workbook.Properties.Title = $"Análise: {dados.NomeTexto}";

                    foreach (var aba in _abas.OrderBy(a => a.Ordem))
                    {
                        Console.Write($"   + Renderizando: {aba.NomeAba}...");
                        var sheet = workbook.Worksheets.Add(aba.NomeAba);

                        try
                        {
                            // Passamos o diretorioDestino onde o Visualizer acabou de salvar as fotos
                            aba.Renderizar(sheet, dados, diretorioDestino);
                            Console.WriteLine(" OK");
                        }
                        catch (Exception exAba)
                        {
                            Console.WriteLine($" ERRO: {exAba.Message}");
                            sheet.Cell(1, 1).Value = $"Erro fatal na aba: {exAba.Message}";
                        }
                    }

                    workbook.SaveAs(caminhoCompleto);
                }

                VisualizadorEtograma.Plotar(
                    dados.Fenotipos.ToList(),
                    diretorioDestino
                );
                Console.WriteLine($"[IO] Relatório finalizado: {caminhoCompleto}");
            }
            catch (Exception ex)
            {
                Console.ForegroundColor = ConsoleColor.Red;
                Console.WriteLine($"[ERRO CRÍTICO] Falha ao gravar arquivo: {ex.Message}");
                Console.ResetColor();
            }
        }
    }
}

using ScottPlot;
using Scriptome.Fingerprint.Modelos;
using Scriptome.Fingerprint.MotoresEtograma;
using Scriptome.Nucleo.Modelos.Fenotipo;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;

namespace Scriptome.Infrastructure.Exportacao
{
    public static class VisualizadorEtograma
    {
        public static void Plotar(List<PerfilPersonagemConsolidado> elenco, string caminhoBase)
        {
            var plot = new Plot();

            var xs = elenco.Select(p => p.Vetorial.EgoismoAltruismo).ToArray();
            var ys = elenco.Select(p => p.Vetorial.ImpulsoNorma).ToArray();
            var zs = elenco.Select(p => p.Vetorial.ConcretoAbstrato).ToArray();

            // =============================
            // PERSONAGENS
            // =============================
            for (int i = 0; i < elenco.Count; i++)
            {
                var cor = CorPorZ(zs[i]);

                var scatter = plot.Add.Scatter(
                    new[] { xs[i] },
                    new[] { ys[i] },
                    color: cor
                );

                scatter.MarkerSize = 9;

                double xLabel = Clamp(xs[i], -0.95, 0.95);
                double yLabel = Clamp(ys[i] + 0.05, -0.95, 0.95);

                var txt = plot.Add.Text(elenco[i].Base.Nome, xLabel, yLabel);
                txt.Alignment = Alignment.LowerCenter;
                txt.FontSize = 11;
            }

            // =============================
            // CENTROIDES
            // =============================
            var centroides = BibliotecaCentroidesEtograma.Criar();

            foreach (var c in centroides)
            {
                var v = c.Value;

                var scatter = plot.Add.Scatter(
                    new[] { v.EgoismoAltruismo },
                    new[] { v.ImpulsoNorma },
                    color: ScottPlot.Colors.Black
                );

                scatter.MarkerSize = 18;
                scatter.MarkerShape = MarkerShape.FilledDiamond;

                plot.Add.Text(
                    c.Key.ToString(),
                    v.EgoismoAltruismo + 0.02,
                    v.ImpulsoNorma + 0.02
                );
            }

            plot.Add.VerticalLine(0, color: ScottPlot.Colors.SteelBlue);
            plot.Add.HorizontalLine(0, color: ScottPlot.Colors.DarkGoldenRod);

            AdicionarLegendaZ(plot);

            plot.Axes.SetLimits(-1, 1, -1, 1);

            plot.Title("Etograma Cartesiano");
            plot.XLabel("Egoísmo ← → Altruísmo");
            plot.YLabel("Impulso ← → Norma");

            Directory.CreateDirectory(caminhoBase);

            var caminho = Path.Combine(caminhoBase, "EtogramaCartesiano.png");
            plot.SavePng(caminho, 1200, 900);
        }

        private static void AdicionarLegendaZ(Plot plot)
        {
            double y = 1.02;

            var tZ = plot.Add.Text("Z", -1, y + 0.06);
            tZ.Bold = true;
            tZ.FontSize = 14;

            var concreto = plot.Add.Text("Concreto", -1, y - 0.02);
            concreto.Color = new ScottPlot.Color(0, 80, 255);
            concreto.Bold = true;
            concreto.FontSize = 13;

            var abstrato = plot.Add.Text("Abstrato", 0.85, y - 0.02);
            abstrato.Color = new ScottPlot.Color(255, 60, 60);
            abstrato.Bold = true;
            abstrato.FontSize = 13;
        }

        private static ScottPlot.Color CorPorZ(double z)
        {
            z = Math.Max(-1, Math.Min(1, z));

            byte r = (byte)((z + 1) * 127);
            byte b = (byte)((1 - z) * 127);

            return new ScottPlot.Color(r, 40, b);
        }

        private static double Clamp(double v, double min, double max)
        {
            return Math.Max(min, Math.Min(max, v));
        }
    }
}

