using Scriptome.Nucleo.Modelos.Analise;
using Scriptome.Nucleo.Modelos.Genoma;
using System;
using System.Collections.Generic;
using System.Text;

namespace Scriptome.Infrastructure.Validador
{
    public sealed class ExecutorValidacaoJung
    {
        private readonly ValidadorJung _validador;

        public ExecutorValidacaoJung(ValidadorJung validador)
        {
            _validador = validador;
        }

        public double Executar(
            IReadOnlyList<PerfilPersonagem> perfis,
            IReadOnlyList<RnaBruto> rnas)
        {
            var comparacoes = new List<ComparacaoJung>();

            for (int i = 0; i < perfis.Count; i++)
            {
                var comparacao =
                    _validador.Executar(perfis[i], rnas[i]);

                comparacoes.Add(comparacao);
            }

            return MetricasDivergencia
                .CalcularTaxaDivergencia(comparacoes);
        }
    }
}

