using System;
using System.Collections.Generic;
using System.Globalization;
using System.IO;
using System.Linq;
using ClosedXML.Excel; // Usa a biblioteca que já tens
using Scriptome.Limbic.Modelos;

namespace Scriptome.Limbic.Dados
{
    public class RepositorioLexicoUnificado
    {
        private IReadOnlyDictionary<string, List<TermoLexical>>? _cache;
        private Dictionary<string, double>? _configuracoes;

        public bool Carregado => _cache != null && _cache.Any();

        public void Carregar(string caminhoInput)
        {
            // 1. Resolver o caminho do ficheiro .xlsx
            string caminhoArquivo = ResolverArquivoExcel(caminhoInput);

            Console.ForegroundColor = ConsoleColor.Yellow;
            Console.WriteLine($"[LÍMBICO] A carregar Excel via ClosedXML: {Path.GetFileName(caminhoArquivo)}");

            if (!File.Exists(caminhoArquivo))
            {
                Console.ForegroundColor = ConsoleColor.Red;
                Console.WriteLine($"[ERRO FATAL] Ficheiro não encontrado: {caminhoArquivo}");
                Console.ResetColor();
                return;
            }

            try
            {
                using (var workbook = new XLWorkbook(caminhoArquivo))
                {
                    // A. Carregar Configurações (Aba 'Config')
                    if (workbook.Worksheets.TryGetWorksheet("Config", out var abaConfig))
                    {
                        CarregarAbaConfig(abaConfig);
                    }

                    // B. Carregar Vocabulário (Aba 'Vocabulario')
                    if (workbook.Worksheets.TryGetWorksheet("Vocabulario", out var abaVocab))
                    {
                        CarregarAbaVocabulario(abaVocab);
                    }
                    else
                    {
                        // Fallback: Tenta a primeira aba se o nome não for exato
                        CarregarAbaVocabulario(workbook.Worksheet(1));
                    }
                }
            }
            catch (Exception ex)
            {
                Console.ForegroundColor = ConsoleColor.Red;
                Console.WriteLine($"[ERRO EXCEL] Certifica-te que o ficheiro não está aberto no Excel.");
                Console.WriteLine($"Detalhe: {ex.Message}");
                Console.ResetColor();
            }
        }

        private void CarregarAbaVocabulario(IXLWorksheet aba)
        {
            var buildCache = new Dictionary<string, List<TermoLexical>>(StringComparer.OrdinalIgnoreCase);

            // Obtém todas as linhas que têm conteúdo (pula o cabeçalho na linha 1)
            var linhas = aba.RangeUsed().RowsUsed().Skip(1);

            int carregados = 0;
            foreach (var linha in linhas)
            {
                try
                {
                    // Mapeamento por células (1=A, 2=B, 3=C...)
                    var termo = new TermoLexical
                    {
                        TermoOriginal = linha.Cell(1).GetString().Trim(),
                        Lema = linha.Cell(2).GetString().Trim().ToUpperInvariant(),
                        Gramatica = ParseEnum(linha.Cell(3).GetString()),
                        Valencia = ParseDouble(linha.Cell(4).GetString()),
                        Intensidade = ParseDouble(linha.Cell(5).GetString()),

                        EmocaoPlutchik = linha.Cell(6).GetString().Trim().ToUpper(),
                        RegistroLacan = linha.Cell(7).GetString().Trim().ToUpper(),
                        Contexto = linha.Cell(8).GetString().Trim().ToUpper(),
                        Geo = linha.Cell(9).GetString().Trim(),

                        // Peso está na coluna 12 (L)
                        PesoRelevancia = (int)ParseDouble(linha.Cell(12).GetString())
                    };

                    // Tratamento de Desvio (Coluna 11 - K)
                    string desvio = linha.Cell(11).GetString().Trim().ToUpper();
                    if (desvio != "NENHUM" && !string.IsNullOrEmpty(desvio))
                        termo.EhDesvio = true;

                    if (string.IsNullOrEmpty(termo.Lema)) continue;

                    if (!buildCache.ContainsKey(termo.Lema))
                        buildCache[termo.Lema] = new List<TermoLexical>();

                    buildCache[termo.Lema].Add(termo);
                    carregados++;
                }
                catch { /* Ignora linha com erro */ }
            }

            _cache = buildCache;

            Console.ForegroundColor = ConsoleColor.Green;
            Console.WriteLine($"[SUCESSO] Vocabulário: {carregados} termos processados.");
            Console.ResetColor();
        }

        private void CarregarAbaConfig(IXLWorksheet aba)
        {
            _configuracoes = new Dictionary<string, double>(StringComparer.OrdinalIgnoreCase);
            var linhas = aba.RangeUsed().RowsUsed().Skip(1);

            foreach (var linha in linhas)
            {
                string chave = linha.Cell(1).GetString().Trim();
                double valor = ParseDouble(linha.Cell(2).GetString());

                if (!string.IsNullOrEmpty(chave))
                    _configuracoes[chave] = valor;
            }
            Console.WriteLine($"[CONFIG] {_configuracoes.Count} parâmetros lidos da aba Config.");
        }

        private string ResolverArquivoExcel(string input)
        {
            if (File.Exists(input) && input.EndsWith(".xlsx")) return input;

            string dir = Directory.Exists(input) ? input : Path.GetDirectoryName(input) ?? "";
            if (string.IsNullOrEmpty(dir)) dir = AppDomain.CurrentDomain.BaseDirectory;

            return Path.Combine(dir, "VocabularioLexico.xlsx");
        }

        public List<TermoLexical>? Buscar(string termo)
        {
            if (_cache != null && _cache.TryGetValue(termo, out var lista)) return lista;

            if (double.TryParse(termo, NumberStyles.Any, CultureInfo.InvariantCulture, out _))
            {
                return new List<TermoLexical> {
                    new TermoLexical { Lema = termo, Gramatica = CategoriaLexica.Numeral, RegistroLacan = "SIMBOLICO", Intensidade = 1, Valencia = 0 }
                };
            }
            return null;
        }

        public double GetConfig(string key, double def) =>
            _configuracoes != null && _configuracoes.TryGetValue(key, out double v) ? v : def;

        private double ParseDouble(string v)
        {
            if (string.IsNullOrWhiteSpace(v)) return 0;
            return double.TryParse(v, NumberStyles.Any, CultureInfo.InvariantCulture, out double r) ? r : 0;
        }

        private CategoriaLexica ParseEnum(string v)
        {
            if (Enum.TryParse<CategoriaLexica>(v.Trim(), true, out var r)) return r;
            return CategoriaLexica.Desconhecido;
        }
    }
}

