        public double ScoreD { get; set; } // Dominância
        public double ScoreE { get; set; } // Ego
        public double ScoreR { get; set; } // Racionalidade
        public double ScoreI { get; set; } // Ironia
        public double ScoreV { get; set; } // Volição
        public double ScoreA { get; set; } // Afeto
        public double ScoreIE { get; set; } // Erudição (Intelecto/Estilo)
        public double ScoreS { get; set; } // Sensorium (Atmosfera)

        // --- ALIASES COMPATÍVEIS (Nomes Longos para Leitura Humana/Excel) ---
        // O MotorLimbic popula estes campos para facilitar o Exportador
        public double ScoreDominancia { get; set; }
        public double ScoreEgo { get; set; }
        public double ScoreRacionalidade { get; set; }
        public double ScoreIronia { get; set; }
        public double ScoreVolicao { get; set; }
        public double ScoreAfeto { get; set; }
        public double ScoreErudicao { get; set; }
        public double ScoreSensorium { get; set; }

        // --- MÉTRICAS DERIVADAS ---
        public double ScoreL { get; set; } // Intensidade Limbica (Dramatismo)
        public double ScoreB { get; set; } // Burst (Tensão Imediata)

        // Aliases Derivados
        public double DramatismoTotal { get; set; }
        public double BurstScore { get; set; }

        // --- METADADOS E VEREDITOS ---
        public string TextoOriginal { get; set; }
        public string Personagem { get; set; }
        public string Veredito { get; set; } // Ex: "Agressivo"
        public string VereditoEmocional { get; set; } // Alias

        public List<string> PalavrasChave { get; set; } = new List<string>();

        // NOVO: Transporte das extensões da Engine
        public Dictionary<string, double> MetadadosExtras { get; set; }
            = new Dictionary<string, double>();
    }
}

