using Scriptome.Limbic.Algoritmos;
using Scriptome.Limbic.Modelos;
using Scriptome.Limbic.Interfaces;
using Scriptome.Nucleo.Modelos.Genoma;
using Scriptome.Linguistica;
using System;
using System.Collections.Generic;
using System.Linq;

namespace Scriptome.Limbic.Motor
{
    /// <summary>
    /// FACADE: Motor Limbic (Orquestrador Cognitivo)
    ///
    /// RESPONSABILIDADE:
    /// 1. Orquestrar o Motor DERIVA (Strategy).
    /// 2. Calcular métricas de segunda ordem:
    ///     - Dramatismo (ScoreL)
    ///     - Burst (Tensão Física)
    /// 3. Consolidar metadados interpretativos:
    ///     - Palavras-chave
    ///     - Veredito dominante
    ///
    /// ARQUITETURA:
    /// - 100% RNA-First.
    /// - Não recebe string.
    /// - Não executa NLP.
    /// - Opera exclusivamente sobre RnaLimbic.
    ///
    /// GARANTIA:
    /// Nenhuma funcionalidade da versão string-based foi removida.
    /// Apenas migrada para operar sobre tokens.
    /// </summary>
    public class MotorLimbic : IMotorLimbic
    {
        private readonly IServicoVocabulario _vocabulario;
        private readonly IMotorDeriva _engineDeriva;

        public MotorLimbic(
            IServicoVocabulario vocabulario,
            IMotorDeriva engineDeriva)
        {
            _vocabulario = vocabulario
                ?? throw new ArgumentNullException(nameof(vocabulario));

            _engineDeriva = engineDeriva
                ?? throw new ArgumentNullException(nameof(engineDeriva));
        }

        /// <summary>
        /// Processa RNA já transcrito pelo Núcleo.
        /// </summary>
        public ResultadoLimbic Processar(RnaLimbic rna)
        {
            if (rna == null)
                throw new ArgumentNullException(nameof(rna));

            var resultado = new ResultadoLimbic
            {
                Personagem = rna.Personagem ?? "DESCONHECIDO",
                //TextoOriginal = rna.TextoOriginal
            };

            // ==============================
            // 1. DERIVA (Motor Vetorial)
            // ==============================

            ResultadoDeriva deriva =
                _engineDeriva.Analisar(
                    rna.Tokens,
                    rna.RawLength);

            // Mapear Scores Primários
            resultado.ScoreD = resultado.ScoreDominancia = deriva.D;
            resultado.ScoreE = resultado.ScoreEgo = deriva.E;
            resultado.ScoreR = resultado.ScoreRacionalidade = deriva.R;
            resultado.ScoreI = resultado.ScoreIronia = deriva.I;
            resultado.ScoreV = resultado.ScoreVolicao = deriva.V;
            resultado.ScoreA = resultado.ScoreAfeto = deriva.A;
            resultado.ScoreIE = resultado.ScoreErudicao = deriva.IE;
            resultado.ScoreS = resultado.ScoreSensorium = deriva.S;

            if (deriva.Extras != null && deriva.Extras.Count > 0)
            {
                resultado.MetadadosExtras =
                    new Dictionary<string, double>(deriva.Extras);
            }

            // ==============================
            // 2. DRAMATISMO (ScoreL)
            // ==============================

            double somaVetores =
                deriva.D + deriva.E + deriva.R +
                deriva.I + deriva.V + deriva.A;

            resultado.ScoreL =
                Math.Min(10,
                Math.Round((somaVetores / 6.0) * 1.2, 2));

            resultado.DramatismoTotal = resultado.ScoreL;

            // ==============================
            // 3. BURST (Token-Based)
            // ==============================

            resultado.ScoreB =
                CalcularBurst(rna.Tokens, deriva.D, deriva.V);

            resultado.BurstScore = resultado.ScoreB;

            // ==============================
            // 4. METADADOS INTERPRETATIVOS
            // ==============================

            PreencherMetadados(resultado, rna);

            return resultado;
        }

        // ==========================================================
        // BURST TOKEN-BASED (Equivalente à versão string)
        // ==========================================================

        private double CalcularBurst(
            IReadOnlyList<Token> tokens,
            double dom,
            double vol)
        {
            if (tokens == null || tokens.Count == 0)
                return 0;

            double score = 0;

            int totalChars =
                tokens.Sum(t => t.Original?.Length ?? 0);

            int totalPalavras =
                tokens.Count(t => !t.EhPontuacao);

            // Comprimento total (substitui texto.Length)
            if (totalChars < 20) score += 40;
            else if (totalChars < 60) score += 20;
            else if (totalChars > 300) score -= 10;

            // Pontuação enfática
            int exclamacoes =
                tokens.Count(t =>
                    t.EhPontuacao &&
                    t.Original != null &&
                    t.Original.Contains("!"));

            score += exclamacoes * 10;

            // Caixa alta dominante
            int upper =
                tokens.Count(t => t.CaixaAlta);

            if (totalPalavras > 0 &&
                ((double)upper / totalPalavras) > 0.8)
            {
                score += 20;
            }

            // Peso vetorial
            score += (dom * 4.0) + (vol * 3.0);

            return Math.Min(100,
                Math.Round(score, 1));
        }

        // ==========================================================
        // METADADOS E VEREDITO
        // ==========================================================

        private void PreencherMetadados(
            ResultadoLimbic res,
            RnaLimbic rna)
        {
            res.PalavrasChave = new List<string>();

            if (res.ScoreD > 6.0)
                res.PalavrasChave.Add("DOMINANTE");

            if (res.ScoreA > 6.0)
                res.PalavrasChave.Add("AFETIVO");

            if (res.ScoreI > 5.0)
                res.PalavrasChave.Add("IRÔNICO");

            if (res.ScoreS > 6.0)
                res.PalavrasChave.Add("SENSORIAL");

            if (res.ScoreIE < 3.0 &&
                rna.RawLength > 20)
            {
                res.PalavrasChave.Add("COLOQUIAL");
            }

            if (res.ScoreB >= 75)
                res.PalavrasChave.Add("ALTA TENSÃO");

            if (res.MetadadosExtras != null &&
                res.MetadadosExtras.TryGetValue(
                    "Informalidade",
                    out double informal) &&
                informal > 5.0)
            {
                res.PalavrasChave.Add("GÍRIA");
            }

            // ==============================
            // VEREDITO DOMINANTE
            // ==============================

            var scores = new Dictionary<string, double>
            {
                { "Agressivo", res.ScoreD },
                { "Emotivo", res.ScoreA },
                { "Racional", res.ScoreR },
                { "Cínico", res.ScoreI },
                { "Determinado", res.ScoreV },
                { "Atmosférico", res.ScoreS }
            };

            var campeao =
                scores.OrderByDescending(x => x.Value)
                      .First();

            res.Veredito =
                campeao.Value > 3.0
                ? campeao.Key
                : "Neutro";

            res.VereditoEmocional = res.Veredito;
        }
    }
}

using Scriptome.Limbic.Modelos;
using Scriptome.Limbic.Motor;
using Scriptome.Nucleo.Modelos.Script;
using Scriptome.Nucleo.Modelos.Genoma;
using Scriptome.Linguistica;
using System.Text.RegularExpressions;

namespace Scriptome.Limbic.Pipeline
{
    /// <summary>
    /// ANALISADOR CONTEXTUAL (Ações - CAVI)
    ///
    /// Responsável por:
    /// 1. Aplicar análise límbica via MotorLimbic (Burst + Dramatismo)
    /// 2. Aplicar impacto vetorial contextual (CAVI)
    ///
    /// RNA-First: utiliza transcrição antes de chamar o MotorLimbic.
    /// </summary>
    public class AnalisadorContextual
    {
        private readonly MotorLimbic _motor;
        private readonly MotorDeTranscricao _transcritor;

        private readonly Dictionary<string, ImpactoVetorial> _lexicoAcao = new()
        {
            { "ARMA", new(5,0,0,2,3,0) }, { "TIRO", new(5,2,0,0,2,0) }, { "MATA", new(5,3,-5,2,3,0) },
            { "SANGUE", new(2,5,0,0,0,0) }, { "SOCO", new(4,3,-2,1,2,0) }, { "TAPA", new(4,3,-2,1,2,1) },
            { "GRITA", new(2,2,-1,1,1,-2) }, { "ORDENA", new(3,0,0,2,2,0) }, { "AMEAÇA", new(3.5,1,-2,1,2,0) },
            { "FUMA", new(1.5,4,0,1,0,1) }, { "CIGARRO", new(1.5,4,0,1,0,1) }, { "BEBE", new(0.5,3,0,0,0,0.5) },
            { "ENCARA", new(2.5,1,0,2,1,1) }, { "OBSERVA", new(1.5,1,0,1,0,2) }, { "SORRISO", new(1,1,0,2,0,3) },
            { "SILÊNCIO", new(1.5,0,0,1,1,2) }, { "IGNORA", new(2,0,-2,4,1,4) }, { "TREME", new(-2,5,2,-2,-3,-1) },
            { "BEIJA", new(1,4,4,0,1,0) }, { "ABRAÇA", new(0.5,3,5,0,0,0) }, { "CHORA", new(-2,3,3,-2,-2,-2) },
            { "SEXO", new(3,5,2,2,3,0) }, { "NU", new(2,5,0,3,0,0) }, { "DESPE", new(3,4,1,2,2,0) }
        };

        public AnalisadorContextual(
            MotorLimbic motor,
            MotorDeTranscricao transcritor)
        {
            _motor = motor;
            _transcritor = transcritor;
        }

        public void Processar(Acao a, ContextoLimbic ctx)
        {
            // =====================================
            // 1. TRANSCRIÇÃO PARA MOTOR LÍMBICO
            // =====================================

            var gene = new GeneDiscursivo(a.Descricao, 0, 0);
            var dna = new BaseImutavel("NARRADOR", new[] { gene });
            var rna = _transcritor.Transcrever(dna);

            var res = _motor.Processar(rna);

            ctx.TotalChars += a.Descricao.Length;
            ctx.CenaBurst += res.ScoreB;
            ctx.ElementosContabilizados++;

            // =====================================
            // 2. CAVI (Impacto Contextual)
            // =====================================

            var impacto = CalcularImpacto(a.Descricao);

            if (Math.Abs(impacto.Dom) > 0.1 || Math.Abs(impacto.Sen) > 0.1)
            {
                double somaAbs =
                    Math.Abs(impacto.Dom) +
                    Math.Abs(impacto.Sen) +
                    Math.Abs(impacto.Afe) +
                    Math.Abs(impacto.Vol) +
                    Math.Abs(impacto.Iro);

                double dramaCtx =
                    Math.Log(1 + somaAbs) * 2.0;

                ctx.CenaDrama += Math.Max(res.ScoreL, dramaCtx);

                if (impacto.Dom > 2.5) ctx.TagsCena.Add("Tensão");
                else if (impacto.Sen > 2.5) ctx.TagsCena.Add("Sensorial");
                else if (impacto.Afe > 2.5) ctx.TagsCena.Add("Afetivo");

                var donos = IdentificarDonos(
                    a.Descricao,
                    ctx.TodosPersonagens,
                    ctx.UltimoSujeito);

                if (donos.Count > 0)
                {
                    ctx.UltimoSujeito = donos[0];

                    foreach (var dono in donos)
                    {
                        var ac = ctx.ObterAcumulador(dono);
                        ac.AcumularContexto(impacto, 1.0);
                        ctx.RegistrarPresenca(dono);
                    }
                }
                else if (ctx.PresentesNaCena.Count > 0)
                {
                    double fator =
                        1.0 / (ctx.PresentesNaCena.Count * 2.0);

                    foreach (var p in ctx.PresentesNaCena)
                    {
                        var ac = ctx.ObterAcumulador(p);
                        ac.AcumularContexto(impacto, fator);
                    }
                }
            }
            else
            {
                ctx.CenaDrama += res.ScoreL;
            }
        }

        // Mantido idêntico ao legado
        private ImpactoVetorial CalcularImpacto(string texto)
        {
            var total = new ImpactoVetorial(0, 0, 0, 0, 0, 0);
            string upper = texto.ToUpper();

            foreach (var kvp in _lexicoAcao)
            {
                if (upper.Contains(kvp.Key))
                {
                    total.Dom += kvp.Value.Dom;
                    total.Sen += kvp.Value.Sen;
                    total.Afe += kvp.Value.Afe;
                    total.Ego += kvp.Value.Ego;
                    total.Vol += kvp.Value.Vol;
                    total.Iro += kvp.Value.Iro;
                }
            }

            return total;
        }

        private List<string> IdentificarDonos(
            string texto,
            HashSet<string> candidatos,
            string ultimo)
        {
            var donos = new List<string>();
            string upper = texto.ToUpper();

            foreach (var nome in candidatos)
                if (Regex.IsMatch(upper, $@"\b{Regex.Escape(nome)}\b"))
                    donos.Add(nome);

            if (donos.Count == 0 && !string.IsNullOrEmpty(ultimo))
            {
                if (Regex.IsMatch(upper, @"\bELE\b") ||
                    Regex.IsMatch(upper, @"\bELA\b"))
                {
                    donos.Add(ultimo);
                }
            }

            return donos;
        }
    }
}

using Scriptome.Limbic.Modelos;
using Scriptome.Limbic.Motor;
using Scriptome.Nucleo.Modelos.Script;
using Scriptome.Nucleo.Modelos.Genoma;
using Scriptome.Linguistica;

namespace Scriptome.Limbic.Pipeline
{
    /// <summary>
    /// ANALISADOR LÉXICO (RNA-First)
    ///
    /// Responsável por:
    /// - Processar falas via MotorLimbic
    /// - Atualizar métricas de ContextoLimbic
    /// - Alimentar acumuladores por personagem
    ///
    /// NÃO contém lógica vetorial.
    /// Apenas orquestra transcrição e consolidação.
    /// </summary>
    public class AnalisadorLexico
    {
        private readonly MotorLimbic _motor;
        private readonly MotorDeTranscricao _transcritor;

        public AnalisadorLexico(
            MotorLimbic motor,
            MotorDeTranscricao transcritor)
        {
            _motor = motor;
            _transcritor = transcritor;
        }

        public void Processar(Dialogo d, ContextoLimbic ctx)
        {
            // ============================
            // 1. TRANSCRIÇÃO DNA → RNA
            // ============================

            string nome = (d.Personagem ?? "DESCONHECIDO")
                .Trim()
                .ToUpper();

            var gene = new GeneDiscursivo(
                d.Texto,
                0,
                0);

            var dna = new BaseImutavel(
                nome,
                new[] { gene });

            var rna = _transcritor.Transcrever(dna);

            // ============================
            // 2. PROCESSAMENTO LÍMBICO
            // ============================

            var res = _motor.Processar(rna);

            // ============================
            // 3. CONTEXTO DE CENA
            // ============================

            ctx.UltimoSujeito = nome;

            if (d.Texto.Split(' ').Length < 10)
                ctx.InteracoesRapidas++;

            ctx.TotalChars += d.Texto.Length;

            ctx.CenaBurst += res.ScoreB;
            ctx.CenaDrama += res.ScoreL;
            ctx.ElementosContabilizados++;

            if (!string.IsNullOrEmpty(res.VereditoEmocional)
                && res.VereditoEmocional != "Neutro")
            {
                ctx.TagsCena.Add(res.VereditoEmocional);
            }

            // ============================
            // 4. ACUMULADOR POR PERSONAGEM
            // ============================

            var ac = ctx.ObterAcumulador(nome);

            ac.Falas++;

            ac.SomaD += res.ScoreD;
            ac.SomaE += res.ScoreE;
            ac.SomaV += res.ScoreV;
            ac.SomaI += res.ScoreI;
            ac.SomaR += res.ScoreR;
            ac.SomaA += res.ScoreA;
            ac.SomaS += res.ScoreS;
            ac.SomaIE += res.ScoreIE;

            ac.SomaBurst += res.ScoreB;
            ac.SomaLimbic += res.ScoreL;
        }
    }
}

using Scriptome.Nucleo.Modelos;
using Scriptome.Nucleo.Modelos.Script;

namespace Scriptome.Limbic.Pipeline
{
    public class ConstrutorDeCena
    {
        public void Inicializar(Cena cena, EstatisticasRoteiro stats, ContextoLimbic ctx)
        {
            ctx.ResetarCena();

            var statExistente = stats.Cenas.FirstOrDefault(c => c.Id == cena.Numero);
            if (statExistente == null)
            {
                statExistente = new EstatisticasCena
                {
                    Id = cena.Numero,
                    Nome = cena.Cabecalho,
                    EstiloCena = "Processando..."
                };
                stats.Cenas.Add(statExistente);
            }

            ctx.StatCena = statExistente;

            foreach (var el in cena.Elementos)
            {
                if (el is Dialogo d)
                {
                    string p = (d.Personagem ?? "").Trim().ToUpper();
                    if (!string.IsNullOrEmpty(p)) ctx.RegistrarPresenca(p);
                }
            }
        }

        public void Finalizar(ContextoLimbic ctx)
        {
            // Mesmo que a cena tenha poucos elementos, precisamos dar um fechamento
            var s = ctx.StatCena;
            if (s == null) return;

            if (ctx.ElementosContabilizados > 0)
            {
                // --- 1. MÉTRICAS FÍSICAS (TENSÃO E DRAMA) ---
                s.BurstScore = Math.Round(ctx.CenaBurst / ctx.ElementosContabilizados, 1);
                s.DramatismoTotal = Math.Round(ctx.CenaDrama / ctx.ElementosContabilizados, 1);

                // --- 2. CÁLCULO DE RITMO (PACING) ---
                // Baseado na densidade de falas e velocidade das palavras (caracteres)
                double ratioInteracao = (double)ctx.InteracoesRapidas / ctx.ElementosContabilizados;
                double mediaChars = (double)ctx.TotalChars / ctx.ElementosContabilizados;
                double velDiscursiva = Math.Max(5, 100 - (mediaChars / 3.0));

                s.PacingScore = Math.Min(100, Math.Round((ratioInteracao * 100 * 0.4) + (velDiscursiva * 0.6), 1));
                s.ClassificacaoRitmo = s.PacingScore > 65 ? "Ágil" : s.PacingScore > 40 ? "Fluido" : "Lento";

                // --- 3. PSICOLOGIA NARRATIVA (VEREDITO E ESTILO) ---
                s.AssinaturaEmocional = ctx.TagsCena.Distinct().ToList();

                if (ctx.TagsCena.Any())
                {
                    // VEREDITO: O tom mais frequente da cena
                    var grupos = ctx.TagsCena.GroupBy(t => t).OrderByDescending(g => g.Count()).ToList();
                    s.VereditoEmocional = grupos.First().Key;

                    // ESTILO CENA: Síntese das duas forças dominantes (O que faltava no Excel)
                    // Exemplo: "Agressivo / Tensão" ou "Racional / Sensorial"
                    s.EstiloCena = string.Join(" / ",
                        grupos.Take(2).Select(g => g.Key));
                }
                else
                {
                    // Fallback para cenas onde o léxico foi neutro ou puramente descritivo
                    s.VereditoEmocional = "Neutro";
                    s.EstiloCena = "Descritivo / Neutro";
                }
            }
            else
            {
                // TRATAMENTO PARA CENAS MUDAS (Ação Pura)
                // Se a CalculadoraSintatica retornar 0.1 conforme planejado, ElementosContabilizados será > 0.
                // Se chegar aqui, a cena estava realmente vazia de conteúdo.
                s.VereditoEmocional = "Visual";
                s.EstiloCena = "Ação Muda / Descritivo";
                s.BurstScore = 10.0;
                s.PacingScore = 20.0;
                s.ClassificacaoRitmo = "Contemplativo";
            }
        }
    }
}

using Scriptome.Nucleo.Modelos;
using Scriptome.Fingerprint.Modelos;
using System.Collections.Generic;
using Scriptome.Nucleo.Modelos.Genoma;

namespace Scriptome.Limbic.Pipeline
{
    // Estrutura de dados para o impacto vetorial de uma ação
    public struct ImpactoVetorial
    {
        public double Dom, Sen, Afe, Ego, Vol, Iro;
        public ImpactoVetorial(double d, double s, double a, double e, double v, double i)
        { Dom = d; Sen = s; Afe = a; Ego = e; Vol = v; Iro = i; }
    }

    // Acumulador de dados brutos por personagem
    public class AcumuladorForense
    {
        public int Falas;
        // Léxico (Dialogo - Vindo do MotorLimbic)
        public double SomaD, SomaE, SomaV, SomaI, SomaR, SomaA, SomaS, SomaIE, SomaBurst, SomaLimbic;
        // Contextual (Ação - Vindo do CAVI)
        public double CtxDom, CtxSen, CtxAfe, CtxEgo, CtxVol, CtxIro;

        public void AcumularContexto(ImpactoVetorial imp, double fator)
        {
            CtxDom += imp.Dom * fator;
            CtxSen += imp.Sen * fator;
            CtxAfe += imp.Afe * fator;
            CtxEgo += imp.Ego * fator;
            CtxVol += imp.Vol * fator;
            CtxIro += imp.Iro * fator;
