using Scriptome.Nucleo.Modelos;
using Scriptome.Nucleo.Modelos.Script;
using Scriptome.Nucleo.Modelos.Analise;
using System;
using System.Linq;
using Scriptome.Nucleo.Interfaces;

namespace Scriptome.Nucleo.Adaptadores
{
    /// <summary>
    /// MÓDULO: Diagnóstico de Saúde do Processamento
    /// FUNÇÃO: Auditar os objetos de estatística final para detectar falhas silenciosas (zeros, nulos, desconexões).
    /// </summary>
    public class AdaptadorDiagnostico : IModuloAnalise
    {
        // Roda por último para verificar o resultado final de todos os módulos anteriores
        public int Ordem => 100;

        public void Analisar(Roteiro roteiro, EstatisticasRoteiro stats)
        {
            ImprimirCabecalho("RELATÓRIO DE DIAGNÓSTICO DO SISTEMA");

            // 1. VERIFICAÇÃO ESTRUTURAL
            VerificarEstrutura(roteiro, stats);

            // 2. AUDITORIA LÉXICA (Emoção)
            VerificarLexico(stats);

            // 3. AUDITORIA FÍSICA (Burst/Ritmo)
            VerificarBurst(stats);

            // 4. AUDITORIA DE PERSONAGENS
            VerificarPersonagens(stats);

            Console.WriteLine("\n-----------------------------------------------------------");
            Console.WriteLine("FIM DO DIAGNÓSTICO");
            Console.WriteLine("-----------------------------------------------------------\n");
        }

        private void VerificarEstrutura(Roteiro roteiro, EstatisticasRoteiro stats)
        {
            Console.WriteLine($"[ESTRUTURA] Cenas no Roteiro: {roteiro.Cenas.Count} | Cenas Processadas: {stats.Cenas.Count}");

            if (stats.Cenas.Count == 0)
            {
                ImprimirErro("CRÍTICO: Nenhuma cena foi registrada nas estatísticas. O loop principal falhou.");
                return;
            }

            if (stats.Cenas.Count != roteiro.Cenas.Count)
            {
                ImprimirAviso($"DIVERGÊNCIA: {roteiro.Cenas.Count - stats.Cenas.Count} cenas foram ignoradas ou perdidas.");
            }
            else
            {
                ImprimirSucesso("Integridade Estrutural OK.");
            }
        }

        private void VerificarLexico(EstatisticasRoteiro stats)
        {
            double mediaDramatismo = stats.MediaDramatismoGlobal;
            int cenasZeradas = stats.Cenas.Count(c => c.DramatismoTotal == 0);

            Console.WriteLine($"\n[LÉXICO] Média Global: {mediaDramatismo:F2}");

            if (mediaDramatismo == 0)
            {
                ImprimirErro("FALHA TOTAL: O Dramatismo Global é ZERO. O dicionário não foi lido ou não houve match.");
            }
            else if (cenasZeradas > 0)
            {
                ImprimirAviso($"ATENÇÃO: {cenasZeradas} cenas ({Percentual(cenasZeradas, stats.Cenas.Count)}) estão com Dramatismo ZERO (Mudas ou erro?).");
            }
            else
            {
                ImprimirSucesso("Cálculo Léxico Ativo em todas as cenas.");
            }

            // Checa keywords
            var cenasSemKeywords = stats.Cenas.Count(c => c.AssinaturaEmocional == null || !c.AssinaturaEmocional.Any());
            if (cenasSemKeywords > 0)
                ImprimirAviso($"KEYWORDS: {cenasSemKeywords} cenas sem assinatura emocional gerada.");
        }

        private void VerificarBurst(EstatisticasRoteiro stats)
        {
            double mediaPacing = stats.MediaPacingGlobal;
            int cenasBurstZero = stats.Cenas.Count(c => c.PacingScore == 0);

            Console.WriteLine($"\n[BURST/RITMO] Média Global: {mediaPacing:F2}");

            if (mediaPacing == 0)
            {
                ImprimirErro("FALHA TOTAL: O Burst Global é ZERO. Verifique a pontuação do texto ou a lógica de acumulação.");
            }
            else if (cenasBurstZero > 0)
            {
                // É normal ter algumas cenas com 0 burst (cenas sem diálogo/ação ou muito curtas), mas não muitas.
                if (cenasBurstZero > stats.Cenas.Count * 0.5)
                    ImprimirErro($"ALERTA: {cenasBurstZero} cenas com Burst ZERO. Isso parece sistêmico.");
                else
                    ImprimirAviso($"INFO: {cenasBurstZero} cenas com Burst ZERO (Provavelmente curtas ou sem pontuação enfática).");
            }
            else
            {
                ImprimirSucesso("Cálculo de Burst Ativo e Distribuído.");
            }
        }

        private void VerificarPersonagens(EstatisticasRoteiro stats)
        {
            Console.WriteLine($"\n[PERSONAGENS] Identificados: {stats.AnalisePersonagens.Count}");

            if (stats.AnalisePersonagens.Count == 0)
            {
                ImprimirAviso("Nenhum perfil de personagem gerado. O roteiro tem diálogos formatados corretamente?");
                return;
            }

            var persSemArquetipo = stats.AnalisePersonagens.Count(p => string.IsNullOrEmpty(p.Arquetipo) || p.Arquetipo == "Desconhecido");
            if (persSemArquetipo > 0)
            {
                ImprimirAviso($"{persSemArquetipo} personagens sem Arquétipo definido.");
            }
            else
            {
                ImprimirSucesso("Todos os personagens receberam classificação arquetípica.");
            }

            // Amostragem
            var top = stats.AnalisePersonagens.OrderByDescending(p => p.DramatismoMedio).FirstOrDefault();
            if (top != null)
                Console.WriteLine($"   > Top Dramatismo: {top.Nome} ({top.DramatismoMedio:F1} - {top.Arquetipo})");
        }

        // --- Auxiliares de Visualização ---
        private void ImprimirCabecalho(string texto)
        {
            Console.ForegroundColor = ConsoleColor.Cyan;
            Console.WriteLine($"\n=== {texto} ===");
            Console.ResetColor();
        }
        private void ImprimirSucesso(string texto)
        {
            Console.ForegroundColor = ConsoleColor.Green;
            Console.WriteLine($"   [OK] {texto}");
            Console.ResetColor();
        }
        private void ImprimirAviso(string texto)
        {
            Console.ForegroundColor = ConsoleColor.Yellow;
            Console.WriteLine($"   [!] {texto}");
            Console.ResetColor();
        }
        private void ImprimirErro(string texto)
        {
            Console.ForegroundColor = ConsoleColor.Red;
            Console.WriteLine($"   [FALHA] {texto}");
            Console.ResetColor();
        }
        private string Percentual(int parte, int todo) => $"{(double)parte / todo:P0}";
    }
}

using Scriptome.Nucleo.Modelos;
using Scriptome.Nucleo.Modelos.Script;
using System;
using System.Linq;
using System.Collections.Generic;
using Scriptome.Nucleo.Interfaces;

namespace Scriptome.Nucleo.Adaptadores
{
    /// <summary>
    /// ADAPTADOR: DINÂMICA & DNA (SÍNTESE FINAL)
    /// Responsável por consolidar as métricas globais e calcular o DNA Narrativo (Octógono).
    /// </summary>
    public class AdaptadorDinamica : IModuloAnalise
    {
        // Ordem 50: Deve rodar após o Limbico e Beats para ter acesso aos scores de cena.
        public int Ordem => 50;

        public void Analisar(Roteiro roteiro, EstatisticasRoteiro stats)
        {
            if (stats.Cenas == null || !stats.Cenas.Any()) return;

            // 1. CÁLCULO DE VISUALIDADE (Show Don't Tell)
            double totalDialogos = Math.Max(1, stats.TotalDialogos);
            stats.IndiceShowDontTell = Math.Round((double)stats.TotalAcoes / totalDialogos, 2);

            if (stats.IndiceShowDontTell > 1.2) stats.DescricaoShowDontTell = "Visual (Show)";
            else if (stats.IndiceShowDontTell < 0.8) stats.DescricaoShowDontTell = "Verborrágico (Tell)";
            else stats.DescricaoShowDontTell = "Equilibrado";

            // 2. CÁLCULO DE VARIABILIDADE (DINÂMICA)
            // Mede a oscilação do ritmo entre as cenas (Desvio Padrão)
            double mediaPacing = stats.MediaPacingGlobal;
            double somaQuadrados = stats.Cenas.Sum(c => Math.Pow(c.PacingScore - mediaPacing, 2));
            double variancia = somaQuadrados / stats.Cenas.Count;
            stats.VariabilidadeRitmo = Math.Round(Math.Sqrt(variancia), 2);

            // Identificação do pico de ritmo
            var cenaPico = stats.Cenas.OrderByDescending(c => c.PacingScore).FirstOrDefault();
            stats.CenaPicoRitmo = cenaPico?.Id ?? 0;

            // 3. SÍNTESE DO DNA GLOBAL (O OCTÓGONO)
            CalcularDnaGlobal(stats);
        }

        private void CalcularDnaGlobal(EstatisticasRoteiro stats)
        {
            if (stats.DnaGlobal == null) stats.DnaGlobal = new Dictionary<string, double>();

            // A. RITMO (0-10): Baseado no Pacing Global
            stats.DnaGlobal["RITMO"] = Math.Round(Math.Clamp(stats.MediaPacingGlobal / 10.0, 0, 10), 1);

            // B. IMPACTO (0-10): Baseado no Dramatismo (L)
            stats.DnaGlobal["IMPACTO"] = Math.Round(stats.MediaDramatismoGlobal, 1);

            // C. CONFLITO (0-10): Baseado na Dominância média dos personagens
            double conflito = stats.AnalisePersonagens.Any() ? stats.AnalisePersonagens.Average(p => p.ScoreDominancia) : 5.0;
            stats.DnaGlobal["CONFLITO"] = Math.Round(Math.Clamp(conflito, 0, 10), 1);

            // D. COMPLEXIDADE (0-10): Baseado na Racionalidade e Vocabulário
            double complexidade = stats.AnalisePersonagens.Any() ? stats.AnalisePersonagens.Average(p => p.ScoreRacionalidade) : 5.0;
            stats.DnaGlobal["COMPLEXIDADE"] = Math.Round(Math.Clamp(complexidade, 0, 10), 1);

            // E. DIÁLOGO (0-10): RESTAURADO
            // Baseado na Erudição (IE) e volume de falas
            double mediaErudicao = stats.AnalisePersonagens.Any() ? stats.AnalisePersonagens.Average(p => p.ScoreErudicao) : 5.0;
            double bonusVocab = stats.TotalDialogos > stats.TotalAcoes ? 1.0 : 0.0;
            stats.DnaGlobal["DIALOGO"] = Math.Round(Math.Clamp(mediaErudicao + bonusVocab, 0, 10), 1);

            // F. ATMOSFERA (0-10): Baseado no Sensorium (S)
            double atmosfera = stats.AnalisePersonagens.Any() ? stats.AnalisePersonagens.Average(p => p.ScoreSensorium) : 5.0;
            stats.DnaGlobal["ATMOSFERA"] = Math.Round(Math.Clamp(atmosfera, 0, 10), 1);

            // G. VISUALIDADE (0-10): Baseado no Show Don't Tell
            // Normalizando o índice (idealmente 1.5 para nota 10)
            stats.DnaGlobal["VISUALIDADE"] = Math.Round(Math.Min(10, stats.IndiceShowDontTell * 6.5), 1);

            // H. DINÂMICA (0-10): RESTAURADO
            // Baseado na Variabilidade calculada no passo anterior. 
            // Uma variabilidade de 25 representa um roteiro muito dinâmico (Nota 10).
            stats.DnaGlobal["DINAMICA"] = Math.Round(Math.Min(10, stats.VariabilidadeRitmo / 2.5), 1);
        }
    }
}

