namespace Scriptome.Nucleo.Especialistas;

public class EspecialistaProducao
{
    public (string perfil, string alerta) AnalisarViabilidade(Dictionary<string, int> horarios, int totalCenas)
    {
        if (totalCenas == 0) return ("Indeterminado", "Sem dados");

        int noites = 0;
        horarios.TryGetValue("NOITE", out noites);
        horarios.TryGetValue("MADRUGADA", out int madrugadas);
        int totalEscuro = noites + madrugadas;

        double percEscuro = (double)totalEscuro / totalCenas;

        // Lógica de Atmosfera Noir
        string perfil = percEscuro > 0.6 ? "Atmosfera Noir Carregada" : "Equilíbrio Urbano";

        // Lógica de Custo de Produção
        string alerta = "Custo Padrão";
        if (percEscuro > 0.7)
            alerta = "ALTO CUSTO: Predomínio noturno exige iluminação e segurança extras.";
        else if (horarios.ContainsKey("AMANHECER") || horarios.ContainsKey("ENTARDECER"))
            alerta = "COMPLEXO: Cenas em 'Hora Mágica' possuem janelas curtas de filmagem.";

        return (perfil, alerta);
    }
}

