namespace Scriptome.Nucleo.Especialistas
{
    /// <summary>
    /// ESPECIALISTA: Analisador de Vocabulário (Diction)
    /// OBJETIVO: Contar a riqueza lexical (palavras únicas) de cada personagem.
    /// </summary>
    public class EspecialistaVocabulario
    {
        public Dictionary<string, int> AnalisarDiction(Roteiro roteiro)
        {
            var vocabularioPorPersonagem = new Dictionary<string, HashSet<string>>();

            foreach (var cena in roteiro.Cenas)
            {
                foreach (var dialogo in cena.Elementos.OfType<Dialogo>())
                {
                    if (string.IsNullOrWhiteSpace(dialogo.Personagem)) continue;

                    if (!vocabularioPorPersonagem.ContainsKey(dialogo.Personagem))
                        vocabularioPorPersonagem[dialogo.Personagem] = new HashSet<string>(StringComparer.OrdinalIgnoreCase);

                    // Tokenização simples
                    var palavras = dialogo.Texto.Split(new[] { ' ', '.', ',', '!', '?', '-', '\n' }, StringSplitOptions.RemoveEmptyEntries);

                    foreach (var p in palavras)
                    {
                        if (p.Length > 2) // Ignora conectivos curtos (de, o, a)
                            vocabularioPorPersonagem[dialogo.Personagem].Add(p.ToLower());
                    }
                }
            }

            // Converte para contagem final
            return vocabularioPorPersonagem.ToDictionary(k => k.Key, v => v.Value.Count);
        }
    }
}

