namespace Scriptome.Nucleo.Leitores
{
    /// <summary>
    /// Leitor de Roteiros no formato Fountain.
    /// </summary>
}
public class LeitorFountain
{
    public Roteiro Parse(string caminhoArquivo)
    {
        var roteiro = new Roteiro();
        var linhas = File.ReadAllLines(caminhoArquivo, Encoding.UTF8);

        // 1. Capturar Título e Autor
        int indiceInicioRoteiro = CapturarMetadados(linhas, roteiro);

        Cena cenaAtual = null;
        Dialogo dialogoAtual = null;
        int contadorCenas = 1; // ESSENCIAL: Garante IDs únicos para a análise

        // 2. Processar o roteiro
        for (int i = indiceInicioRoteiro; i < linhas.Length; i++)
        {
            string linha = linhas[i].Trim();

            if (string.IsNullOrWhiteSpace(linha))
            {
                dialogoAtual = null;
                continue;
            }

            // Identificação de Cabeçalhos (INT. ou EXT.)
            if (linha.StartsWith("INT.", StringComparison.OrdinalIgnoreCase) ||
                linha.StartsWith("EXT.", StringComparison.OrdinalIgnoreCase))
            {
                cenaAtual = ProcessarCabecalhoCena(linha);
                cenaAtual.Numero = contadorCenas++; // Atribui o ID que o ModuloEstatisticas usará
                roteiro.Cenas.Add(cenaAtual);
                continue;
            }

            // Identificação de Personagens
            if (EsPersonagem(linha))
            {
                string nomeLimpo = Regex.Replace(linha, @"\s?\(.*\)$", "").Trim();
                dialogoAtual = new Dialogo { Personagem = nomeLimpo };
                cenaAtual?.Elementos.Add(dialogoAtual);
                continue;
            }

            // Texto de Diálogo ou Ação
            if (dialogoAtual != null && string.IsNullOrEmpty(dialogoAtual.Texto))
            {
                dialogoAtual.Texto = linha;
            }
            else if (cenaAtual != null)
            {
                cenaAtual.Elementos.Add(new Acao { Descricao = linha });
            }
        }
        return roteiro;
    }

    private int CapturarMetadados(string[] linhas, Roteiro roteiro)
    {
        int i = 0;
        for (; i < linhas.Length; i++)
        {
            string linha = linhas[i].Trim();
            if (string.IsNullOrWhiteSpace(linha) && !string.IsNullOrEmpty(roteiro.Titulo)) break;
            if (linha.StartsWith("INT.") || linha.StartsWith("EXT.")) break;

            if (linha.Contains(":"))
            {
                var partes = linha.Split(':', 2);
                string chave = partes[0].Trim().ToLower();
                string valor = partes[1].Trim();

                if (chave == "title" || chave == "título") roteiro.Titulo = valor;
                else if (chave == "author" || chave == "autor") roteiro.Autor = valor;
            }
            else if (i == 0 && !string.IsNullOrWhiteSpace(linha))
            {
                roteiro.Titulo = linha;
            }
        }
        return i;
    }

    private Cena ProcessarCabecalhoCena(string linha)
    {
        // Nota: Se o seu model 'Cena' não possuir a propriedade 'Tipo', remova a atribuição abaixo.
        var cena = new Cena();

        var partes = linha.Split(new[] { '.', '-', ' ' }, StringSplitOptions.RemoveEmptyEntries);

        // Define Localização (ex: CABARÉ) e Momento (ex: DIA)
        cena.Locacao = partes.Length >= 2 ? partes[1].ToUpper() : "NÃO IDENTIFICADA";
        cena.Momento = partes.Last().ToUpper();

        return cena;
    }

    private bool EsPersonagem(string linha)
    {
        if (string.IsNullOrWhiteSpace(linha)) return false;

        // 1. Normalização para validação (remove CONT'D, etc)
        string nomeBase = Regex.Replace(linha, @"\s?\(.*\)$", "").Trim();

        // 2. Trava de Comprimento: Nomes de personagens raramente têm apenas 1 letra.
        // Isso elimina o "É", "A", "O" que podem aparecer isolados.
        if (nomeBase.Length <= 1) return false;

        if (linha.EndsWith(".") && !linha.EndsWith(")")) return false;

        // 3. Lista de Exclusão (Palavras comuns em caixa alta que não são nomes)
        string[] palavrasProibidas = { "É", "DO", "DA", "NO", "NA", "UM", "SE" };
        if (palavrasProibidas.Contains(nomeBase)) return false;

        // 4. Regras que já tínhamos:
        bool ehCaixaAlta = linha == linha.ToUpper();
        bool naoEhCena = !linha.StartsWith("INT.") && !linha.StartsWith("EXT.");

        char[] pontuacaoProibida = { ',', ':', '!', '?' };
        bool semPontuacaoFrase = !nomeBase.Any(c => pontuacaoProibida.Contains(c));

        bool tamanhoOk = linha.Length < 45;

        return ehCaixaAlta && naoEhCena && semPontuacaoFrase && tamanhoOk;
    }


}

