namespace Scriptome.Nucleo.Motores
{
    public sealed class MotorSplicing : IMotorSplicing
    {
        public ResultadoSplice Extrair(
            RnaBruto rna,
            params string[] chaves)
        {
            var resultado = new Dictionary<string, double>();

            foreach (var chave in chaves)
            {
                switch (chave)
                {
                    case "D": resultado["D"] = rna.D; break;
                    case "E": resultado["E"] = rna.E; break;
                    case "R": resultado["R"] = rna.R; break;
                    case "I": resultado["I"] = rna.I; break;
                    case "V": resultado["V"] = rna.V; break;
                    case "A": resultado["A"] = rna.A; break;
                    case "IE": resultado["IE"] = rna.IE; break;
                    case "S": resultado["S"] = rna.S; break;

                    default:
                        if (rna.Extras.ContainsKey(chave))
                            resultado[chave] = rna.Extras[chave];
                        break;
                }
            }

            return new ResultadoSplice(resultado);
        }
    }
}

using Scriptome.Fingerprint.Interfaces;
