using Scriptome.Nucleo.Modelos.Fenotipo;

namespace Scriptome.Fingerprint.Classificadores.Energia
{
    /// <summary>
    /// CLASSIFICADOR ENERGÉTICO V2 (IMUTÁVEL).
    ///
    /// Deriva intensidade, clima termodinâmico e índices de perversidade
    /// exclusivamente a partir do genótipo linguístico.
    /// </summary>
    public class ClassificadorEnergia_V2
    {
        public ExpressaoEnergetica Classificar(ResultadoBaseLinguistico baseLinguistica)
        {
            // --- INTENSIDADE ---
            double intensidade = CalcularIntensidade(baseLinguistica);
            string classificacaoIntensidade =
                intensidade > 7 ? "Alta" :
                intensidade > 4 ? "Média" :
                "Baixa";

            // --- TERMODINÂMICA ---
            string clima = CalcularClima(baseLinguistica);

            // --- PERVERSIDADE ---
            double crueldade = baseLinguistica.ScoreDominancia * 0.6;
            double manipulacao = baseLinguistica.ScoreEgo * 0.5;
            double erotizacao = baseLinguistica.ScoreAfeto * 0.4;

            double indicePerversidade =
                (crueldade + manipulacao + erotizacao) / 3.0;

            string classificacaoPerversidade =
                indicePerversidade > 6 ? "Alta" :
                indicePerversidade > 3 ? "Moderada" :
                "Baixa";

            return new ExpressaoEnergetica(
                IntensidadeDiscursiva: intensidade,
                ClassificacaoIntensidade: classificacaoIntensidade,
                ClimaTermico: clima,
                NivelCrueldade: crueldade,
                NivelManipulacao: manipulacao,
                NivelErotizacao: erotizacao,
                IndicePerversidade: indicePerversidade,
                ClassificacaoPerversidade: classificacaoPerversidade
            );
        }

        private double CalcularIntensidade(ResultadoBaseLinguistico b)
        {
            return (
                b.ScoreDominancia +
                b.ScoreVolicao +
                b.BurstMedio
            ) / 3.0;
        }

        private string CalcularClima(ResultadoBaseLinguistico b)
        {
            double eixo = b.ScoreAfeto - b.ScoreIronia;

            if (eixo > 2) return "Quente";
            if (eixo < -2) return "Frio";
            return "Neutro";
        }
    }
}

using Scriptome.Fingerprint.Interfaces;
using Scriptome.Fingerprint.Modelos;
using Scriptome.Nucleo.Modelos.Analise;
using System;

namespace Scriptome.Fingerprint.Classificadores.Energia
{
    public class ClassificadorIntensidade : IClassificadorIndividual
    {
        public string Nome => "Intensidade Psíquica";

        public void Classificar(PerfilPersonagem p, Etograma e)
        {
            // MANTIDO: Lógica original de cálculo
            double energia =
                (p.ScoreDominancia +
                 p.ScoreVolicao +
                 p.ScoreAfeto +
                 p.ScoreEgo) / 4.0;

            double bonusBurst =
                Math.Clamp((p.BurstMedio - 30) / 30.0, 0, 1.0);

            // Resultado Numérico
            e.IntensidadeDiscursiva =
                Math.Round(Math.Clamp(energia + bonusBurst, 0, 10), 1);

            // CORREÇÃO: Definição da Classificação Textual (Evita 'Indefinida')
            if (e.IntensidadeDiscursiva > 7.5) e.ClassificacaoIntensidade = "Explosiva";
            else if (e.IntensidadeDiscursiva > 5.5) e.ClassificacaoIntensidade = "Alta";
            else if (e.IntensidadeDiscursiva > 3.5) e.ClassificacaoIntensidade = "Moderada";
            else if (e.IntensidadeDiscursiva > 1.5) e.ClassificacaoIntensidade = "Contida";
            else e.ClassificacaoIntensidade = "Fugaz";
        }
    }
}

using Scriptome.Fingerprint;
using Scriptome.Fingerprint.Interfaces;
using Scriptome.Fingerprint.Modelos;
using Scriptome.Nucleo.Modelos.Analise;
using System;
using System.Collections.Generic;
using System.Linq;

namespace Scriptome.Fingerprint.Classificadores.Energia
{
    public class ClassificadorTermico : IClassificadorIndividual
    {
        public string Nome => "Termodinâmica Híbrida (Universal + Local)";

        // 1. INDIVIDUAL
        public void Classificar(PerfilPersonagem p, Etograma e)
        {
            // Calor (Expansão) vs Frio (Contração)
            // Escala esperada: -10 a +10
            double calor = p.ScoreDominancia + p.ScoreVolicao + p.ScoreEgo + (p.ScoreAfeto * 0.5);
            double frio = p.ScoreRacionalidade + p.ScoreIronia + p.ScoreErudicao;
            double deltaBruto = calor - frio;

            // Armazena bruto (temporariamente usando o campo ScoreReal ou criando um auxiliar se preferir, 
            // mas aqui vamos recalcular no loop de grupo para simplificar o DTO)

            // Fallback Universal
            double zUniversal = CalcularZUniversal(deltaBruto);
            e.Termodinamica = DefinirClima(zUniversal);
            p.ArquetipoTermico = e.Termodinamica;
        }

        // 2. GRUPO
        public void ClassificarElenco(List<PerfilPersonagem> elenco)
        {
            if (elenco == null || !elenco.Any()) return;

            // Recalcula os Deltas Brutos
            var deltas = new Dictionary<string, double>();
            foreach (var p in elenco)
            {
                double calor = p.ScoreDominancia + p.ScoreVolicao + p.ScoreEgo + (p.ScoreAfeto * 0.5);
                double frio = p.ScoreRacionalidade + p.ScoreIronia + p.ScoreErudicao;
                deltas[p.Nome] = calor - frio;
            }

            double mediaLocal = deltas.Values.Average();
            double desvioLocal = EstatisticaForense.DesvioPadrao(deltas.Values);

            // Ajuste de Peso (Se o filme é monótono, confiamos mais no universal)
            double pesoLocal = (desvioLocal < 2.0) ? 0.2 : 0.4;
            double pesoUniversal = 1.0 - pesoLocal;

            foreach (var p in elenco)
            {
                double val = deltas[p.Nome];

                double zUniversal = CalcularZUniversal(val);
                double zLocal = EstatisticaForense.ZScore(val, mediaLocal, desvioLocal);

                // Fusão
                double zFinal = (zUniversal * pesoUniversal) + (zLocal * pesoLocal);

                p.Etograma.Termodinamica = DefinirClima(zFinal);
                p.ArquetipoTermico = p.Etograma.Termodinamica;
            }
        }

        // No Universal, o zero é neutro e o desvio padrão é aprox 3.5
        private double CalcularZUniversal(double raw)
        {
            return raw / 3.5;
        }

        private string DefinirClima(double z)
        {
            if (z > 1.0) return "🔥 FOGO (Alto)";
            if (z > 0.3) return "⛅ AR (Morno)";
            if (z > -0.3) return "💧 ÁGUA (Neutro)";
            return "🧊 GELO (Baixo)";
        }
    }
}

using Scriptome.Fingerprint.Dados;
using Scriptome.Fingerprint.Interfaces;
using Scriptome.Fingerprint.Modelos;
using Scriptome.Nucleo.Interfaces;
using Scriptome.Nucleo.Modelos.Fenotipo;
using Scriptome.Nucleo.Modelos.Genoma;
using System;
using System.Collections.Generic;
using System.Linq;

namespace Scriptome.Fingerprint.Classificadores.Narrativa
{
    /// <summary>
    /// CLASSIFICADOR NARRATIVO V2 (RNA-Based)
    ///
    /// - Mesmo padrão estrutural de Jung / MBTI / Lacan
    /// - Apenas RNA + Splicing
    /// - Regras declarativas preservadas integralmente
    /// </summary>
    public sealed class ClassificadorNarrativaV2
        : IClassificadorNarrativaV2
    {
        private static readonly ArquetipoNarrativo[] _todos =
            Enum.GetValues(typeof(ArquetipoNarrativo))
                .Cast<ArquetipoNarrativo>()
                .ToArray();

        private readonly List<RegraArquetipo> _regras;
        private readonly IMotorSplicing _splicing;

        public string Nome => "Narrativa Unificada V2 (RNA-Based)";

        public ClassificadorNarrativaV2(IMotorSplicing splicing)
        {
            _splicing = splicing
                ?? throw new ArgumentNullException(nameof(splicing));

            _regras = InicializarRegras();
        }

        public ExpressaoNarrativa Classificar(
            RnaBruto rna,
            int quantidadeFalas,
            ExpressaoEnergetica energia,
            ExpressaoPsicodinamica psico)
        {
            if (rna == null)
                return GerarExpressao(ArquetipoNarrativo.Indefinido);

            var splice = _splicing.Extrair(
                rna,
                "D", "E", "R", "I", "V", "A", "IE", "S"
            );

            var baseReconstruido = new ResultadoBaseLinguistico
            (
                Nome: string.Empty,
                QuantidadeFalas: quantidadeFalas,
                DramatismoMedio: 0,
                BurstMedio: 0,

                ScoreDominancia: splice.Get("D"),
                ScoreEgo: splice.Get("E"),
                ScoreRacionalidade: splice.Get("R"),
                ScoreIronia: splice.Get("I"),
                ScoreVolicao: splice.Get("V"),
                ScoreAfeto: splice.Get("A"),
                ScoreErudicao: splice.Get("IE"),
                ScoreSensorium: splice.Get("S"),

                DnaVisual: string.Empty,
                KarmaMoral: 0,
                KarmaOrdem: 0,
                AlinhamentoMoral: string.Empty
            );

            if (baseReconstruido.QuantidadeFalas <= 4)
                return GerarExpressao(ArquetipoNarrativo.Figurante);

            var ctx = new ContextoNarrativo(baseReconstruido, energia, psico);

            var scores = _todos.ToDictionary(a => a, _ => 0.0);

            foreach (var regra in _regras)
            {
                if (regra.Condicao(ctx))
                    scores[regra.Arquetipo] += regra.Peso;
            }

            AplicarModulacaoLacaniana(scores, ctx.Psico.RegistroDominante);

            var vencedor = scores
                .OrderByDescending(x => x.Value)
                .ThenByDescending(_ => ctx.Base.ScoreDominancia)
                .ThenByDescending(_ => ctx.Base.ScoreVolicao)
                .First();

            var final = vencedor.Value < 1.0
                ? ArquetipoNarrativo.Indefinido
                : vencedor.Key;

            return GerarExpressao(final);
        }

        // ===============================
        // REGRAS (INALTERADAS)
        // ===============================

        private List<RegraArquetipo> InicializarRegras()
        {
            return new List<RegraArquetipo>
            {
                new(ArquetipoNarrativo.HeroiClassico, 3.0,
                    c => c.Base.ScoreVolicao > 0.6 && c.Base.ScoreAfeto > 0.3),

                // (mantém TODAS as demais regras exatamente como estão)
            };
        }

        private void AplicarModulacaoLacaniana(
            Dictionary<ArquetipoNarrativo, double> scores,
            string registroDominante)
        {
            const double fator = 1.12;

            void Mult(params ArquetipoNarrativo[] a)
            {
                foreach (var arq in a)
                    if (scores[arq] > 0)
                        scores[arq] *= fator;
            }

            if (registroDominante == "REAL")
                Mult(ArquetipoNarrativo.Predador,
                     ArquetipoNarrativo.Psicopata,
                     ArquetipoNarrativo.Sadico,
                     ArquetipoNarrativo.Valentao);

            else if (registroDominante == "SIMBÓLICO")
                Mult(ArquetipoNarrativo.Juiz,
                     ArquetipoNarrativo.Patriarca,
                     ArquetipoNarrativo.Matriarca,
                     ArquetipoNarrativo.Mentor,
                     ArquetipoNarrativo.Cientista);

            else if (registroDominante == "IMAGINÁRIO")
                Mult(ArquetipoNarrativo.Sedutor,
                     ArquetipoNarrativo.Camaleao,
                     ArquetipoNarrativo.Trickster,
                     ArquetipoNarrativo.Galante,
                     ArquetipoNarrativo.Amante);
        }

        private ExpressaoNarrativa GerarExpressao(ArquetipoNarrativo a)
            => new ExpressaoNarrativa(
                a.ToString(),
                BibliotecaArquetipos.ObterDescricao(a)
            );
    }
}

using Scriptome.Fingerprint.Interfaces;
using Scriptome.Fingerprint.Modelos;
using Scriptome.Nucleo.Modelos.Analise;
using System;
using System.Collections.Generic;
using System.Linq;

namespace Scriptome.Fingerprint.Classificadores.Narrativa
{
    public class ClassificadorScriptome : IClassificadorIndividual
    {
        public string Nome => "SÍNTESE NARRATIVA SCRIPTOME 6.1 (Ajuste Fino)";

        public void Classificar(PerfilPersonagem p, Etograma e)
        {
            // -------------------------------------------------
            // 0 — PREMISSA: FIGURANTE
            // -------------------------------------------------
            if (p.QuantidadeFalas <= 4)
            {
                e.ArquetipoNarrativoFinal = ArquetipoNarrativo.Figurante;
                return;
            }

            var scores = InicializarScores();

            // Variáveis Auxiliares
            bool ironiaAmarga = p.ScoreIronia > 0.4 && p.ScoreAfeto < -0.1;
            bool violenciaFria = e.NivelCrueldade > 4 && p.ScoreRacionalidade > 0.5;
            bool seducaoFatal = e.NivelErotizacao > 5 && e.NivelManipulacao > 4;

            // =================================================================
            // GRUPO 1: PROTAGONISTAS
            // =================================================================

            // Heroi Clássico
            if (p.ScoreVolicao > 0.6 && p.ScoreAfeto > 0.3)
                scores[ArquetipoNarrativo.HeroiClassico] += 3.0;

            // Anti-Herói (Ajustado: Baixadinha de 4.0 para 3.0)
            if (p.ScoreVolicao > 0.5 && (ironiaAmarga || e.NivelManipulacao > 3))
                scores[ArquetipoNarrativo.AntiHeroi] += 3.0;

            // Sobrevivente
            if (p.ScoreVolicao > 0.6 && p.ScoreDominancia < 0.5)
                scores[ArquetipoNarrativo.Sobrevivente] += 4.0;

            // Buscador
            if (p.ScoreVolicao > 0.5 && p.ScoreSensorium > 0.6)
                scores[ArquetipoNarrativo.Buscador] += 2.0;

            // Visionário
            if (p.ScoreVolicao > 0.7 && p.ScoreRacionalidade > 0.7)
                scores[ArquetipoNarrativo.Visionario] += 3.0;

            // Competidor
            if (p.ScoreDominancia > 0.6 && p.ScoreVolicao > 0.6)
                scores[ArquetipoNarrativo.Competidor] += 3.0;

            // Bon Vivant
            if (p.ScoreSensorium > 0.7 && p.ScoreVolicao < 0.4)
                scores[ArquetipoNarrativo.BonVivant] += 3.0;

            // Adrenalista
            if (p.ScoreSensorium > 0.8 && p.ScoreVolicao > 0.6)
                scores[ArquetipoNarrativo.Adrenalista] += 3.0;


            // =================================================================
            // GRUPO 2: ANTAGONISTAS
            // =================================================================

            // Tirano
            if (p.ScoreDominancia > 0.7 && p.ScoreAfeto < -0.2)
                scores[ArquetipoNarrativo.Tirano] += 3.0;

            // Psicopata
            if (e.NivelCrueldade > 7 && Math.Abs(p.ScoreAfeto) < 0.2)
                scores[ArquetipoNarrativo.Psicopata] += 5.0;

            // Sádico
            if (e.NivelCrueldade > 5 && (p.ScoreIronia > 0.4 || p.ScoreSensorium > 0.5))
                scores[ArquetipoNarrativo.Sadico] += 3.0;

            // Predador
            if (violenciaFria)
                scores[ArquetipoNarrativo.Predador] += 4.0;

            // Rival
            if (p.ScoreDominancia > 0.5 && p.ScoreVolicao > 0.5)
                scores[ArquetipoNarrativo.Rival] += 2.0;

            // Valentão
            if (p.ScoreDominancia > 0.6 && p.ScoreRacionalidade < 0.4 && e.NivelCrueldade > 3)
                scores[ArquetipoNarrativo.Valentao] += 4.0;

            // Manipulador
            if (e.NivelManipulacao > 6)
                scores[ArquetipoNarrativo.Manipulador] += 3.0;


            // =================================================================
            // GRUPO 3: MEDIADORES
            // =================================================================

            // Malandro
            if (p.ScoreIronia > 0.4 && e.NivelManipulacao > 4 && p.ScoreVolicao > 0.3)
                scores[ArquetipoNarrativo.Malandro] += 4.0;

            // Camaleão
            if (e.NivelManipulacao > 6 && p.ScoreDominancia < 0.4)
                scores[ArquetipoNarrativo.Camaleao] += 3.0;

            // Rebelde
            if (p.ScoreDominancia > 0.4 && p.ScoreIronia > 0.5)
                scores[ArquetipoNarrativo.Rebelde] += 2.0;

            // Fora da Lei
            if (p.ScoreVolicao > 0.5 && p.ScoreRacionalidade > 0.4 && p.ScoreAfeto < 0.2)
                scores[ArquetipoNarrativo.ForaDaLei] += 4.0;

            // Trickster (Requer manipulação ativa para não ser só um bufão)
            if (p.ScoreIronia > 0.7 && p.ScoreSensorium > 0.6 && e.NivelManipulacao > 5)
                scores[ArquetipoNarrativo.Trickster] += 3.0;

            // Enigma
            if (p.ScoreRacionalidade < 0.3 && Math.Abs(p.ScoreAfeto) < 0.2)
                scores[ArquetipoNarrativo.Enigma] += 3.0;

            // Pivô do Caos
            if (p.QuantidadeFalas > 20 && p.ScoreVolicao < 0.3 && e.NivelErotizacao > 4)
                scores[ArquetipoNarrativo.PivoDoCaos] += 3.0;


            // =================================================================
            // GRUPO 4: MENTORES
            // =================================================================

            // Mentor
            if (p.ScoreRacionalidade > 0.6 && p.ScoreAfeto > 0.1)
                scores[ArquetipoNarrativo.Mentor] += 3.0;

            // Juiz
            if (p.ScoreRacionalidade > 0.8 && p.ScoreAfeto < 0.2)
                scores[ArquetipoNarrativo.Juiz] += 3.0;

            // Patriarca
            if (p.ScoreDominancia > 0.7 && p.ScoreAfeto > 0.3)
                scores[ArquetipoNarrativo.Patriarca] += 3.0;

            // Matriarca
            if (p.ScoreAfeto > 0.7 && p.ScoreDominancia > 0.4)
                scores[ArquetipoNarrativo.Matriarca] += 4.0;

            // Cientista
            if (p.ScoreRacionalidade > 0.9)
                scores[ArquetipoNarrativo.Cientista] += 4.0;

            // Guru
            if (p.ScoreDominancia > 0.5 && p.ScoreIronia > 0.5)
                scores[ArquetipoNarrativo.Guru] += 2.0;

            // Idealista
            if (p.ScoreRacionalidade > 0.6 && p.ScoreVolicao > 0.5 && p.ScoreSensorium < 0.4)
                scores[ArquetipoNarrativo.Idealista] += 2.0;

            // Soldado
            if (p.ScoreVolicao > 0.6 && p.ScoreDominancia < 0.4)
                scores[ArquetipoNarrativo.Soldado] += 2.0;


            // =================================================================
            // GRUPO 5: RELACIONAIS
            // =================================================================

            // Mártir
            if (p.ScoreAfeto > 0.6 && p.ScoreDominancia < 0.3)
                scores[ArquetipoNarrativo.Martir] += 3.0;

            // Penitente
            if (p.ScoreAfeto < -0.3 && p.ScoreVolicao > 0.5)
                scores[ArquetipoNarrativo.Penitente] += 4.0;

            // Masoquista
            if (p.ScoreVolicao > 0.5 && p.ScoreDominancia < 0.2)
                scores[ArquetipoNarrativo.Masoquista] += 2.0;

            // Cuidador
            if (p.ScoreAfeto > 0.8)
                scores[ArquetipoNarrativo.Cuidador] += 4.0;

            // Amante
            if (p.ScoreAfeto > 0.5 && p.ScoreSensorium > 0.5)
                scores[ArquetipoNarrativo.Amante] += 2.0;

            // Sedutor (Ajustado: Baixadinha de 6.0 para 4.5)
            // Ainda requer erotização e manipulação, mas não garante vitória automática.
            if (seducaoFatal)
                scores[ArquetipoNarrativo.Sedutor] += 4.5;

            // Galante
            if (p.ScoreSensorium > 0.6 && p.ScoreDominancia > 0.5)
                scores[ArquetipoNarrativo.Galante] += 2.0;

            // Diletante
            if ((p.ScoreSensorium > 0.5 || p.ScoreRacionalidade > 0.5) && p.ScoreVolicao < 0.4)
                scores[ArquetipoNarrativo.Diletante] += 4.0;

            // Inocente
            if (p.ScoreAfeto > 0.4 && p.ScoreIronia < 0.2)
                scores[ArquetipoNarrativo.Inocente] += 3.0;


            // =================================================================
            // GRUPO 6: SOCIAIS
            // =================================================================

            // Conformista
            if (Math.Abs(p.ScoreDominancia) < 0.2 && Math.Abs(p.ScoreIronia) < 0.2)
                scores[ArquetipoNarrativo.Conformista] += 2.0;

            // Solitário
            if (p.ScoreAfeto < 0.1 && p.ScoreDominancia < 0.3)
                scores[ArquetipoNarrativo.Solitario] += 3.0;

            // Rabugento (Captura a ironia amarga, impedindo falso positivo de Bufão)
            if (ironiaAmarga)
            {
                scores[ArquetipoNarrativo.Rabugento] += 4.0;
                scores[ArquetipoNarrativo.Bufao] -= 5.0;
            }

            // Excêntrico
            if (p.ScoreRacionalidade < 0.3 && p.ScoreIronia > 0.6)
                scores[ArquetipoNarrativo.Excentrico] += 3.0;

            // Bufão (Somente se for engraçado sem dor/crueldade)
            if (p.ScoreIronia > 0.8 && p.ScoreAfeto > -0.1 && e.NivelCrueldade < 2)
                scores[ArquetipoNarrativo.Bufao] += 3.0;


            // -------------------------------------------------
            // DECISÃO FINAL
            // -------------------------------------------------
            var vencedor = scores
                .OrderByDescending(x => x.Value)
                .First();

            if (vencedor.Value < 1.0)
                e.ArquetipoNarrativoFinal = ArquetipoNarrativo.Indefinido;
            else
                e.ArquetipoNarrativoFinal = vencedor.Key;
        }

        private Dictionary<ArquetipoNarrativo, double> InicializarScores()
        {
            return Enum.GetValues(typeof(ArquetipoNarrativo))
                .Cast<ArquetipoNarrativo>()
                .ToDictionary(a => a, a => 0.0);
        }
    }
}

