namespace Scriptome.Fingerprint.Classificadores.Psique
{
    public sealed class ClassificadorLacanianoV2
        : IClassificadorLacanianoV2
    {
        private readonly IMotorSplicing _splicing;

        public string Nome => "Topologia Lacaniana V2 (RNA-Based)";

        public ClassificadorLacanianoV2(IMotorSplicing splicing)
        {
            _splicing = splicing
                ?? throw new ArgumentNullException(nameof(splicing));
        }

        // ===============================
        // INDIVIDUAL
        // ===============================
        public ResultadoLacaniano Classificar(RnaBruto rna)
        {
            if (rna == null)
                return ResultadoVazio();

            var f = _splicing.Extrair(
                rna,
                "E", "S", "A",
                "R", "IE",
                "V", "D",
                "I", "BURST"
            );

            double intensidadeI =
                (f.Get("E") * 2.0 +
                 f.Get("S") +
                 f.Get("A")) / 4.0;

            double intensidadeS =
                (f.Get("R") * 1.5 +
                 f.Get("IE")) / 2.5;

            double burstNorm =
                Math.Clamp(f.Get("BURST") / 5.0, 0, 10);

            double intensidadeR =
                (f.Get("V") * 2.0 +
                 f.Get("D") +
                 burstNorm) / 4.0;

            intensidadeI = Math.Round(intensidadeI, 2);
            intensidadeS = Math.Round(intensidadeS, 2);
            intensidadeR = Math.Round(intensidadeR, 2);

            double total = intensidadeI + intensidadeS + intensidadeR;

            double scoreI = 0;
            double scoreS = 0;
            double scoreR = 0;
            string registro = "INDEFINIDO";
            string estrutura = "Indefinida";

            if (total > 0.01)
            {
                scoreI = Math.Round((intensidadeI / total) * 10, 2);
                scoreS = Math.Round((intensidadeS / total) * 10, 2);
                scoreR = Math.Round((intensidadeR / total) * 10, 2);

                var mapa = new Dictionary<string, double>
                {
                    { "IMAGINÁRIO", scoreI },
                    { "SIMBÓLICO", scoreS },
                    { "REAL", scoreR }
                };

                registro = mapa.Values.Distinct().Count() == 1
                    ? "EQUILIBRADO"
                    : mapa.OrderByDescending(x => x.Value).First().Key;

                estrutura = Diagnosticar(registro, intensidadeR, intensidadeS);
            }

            return new ResultadoLacaniano(
                EstruturaPsiquica: estrutura,
                RegistroDominante: registro,
                IntensidadeReal: intensidadeR,
                IntensidadeSimbolico: intensidadeS,
                IntensidadeImaginario: intensidadeI,
                ScoreReal: scoreR,
                ScoreSimbolico: scoreS,
                ScoreImaginario: scoreI
            );
        }

        // ===============================
        // ELENCO (opcional)
        // ===============================
        public Dictionary<RnaBruto, ResultadoLacaniano> ClassificarElenco(
            IReadOnlyList<RnaBruto> elenco)
        {
            var resultado = new Dictionary<RnaBruto, ResultadoLacaniano>();

            if (elenco == null || elenco.Count == 0)
                return resultado;

            foreach (var rna in elenco)
                resultado[rna] = Classificar(rna);

            return resultado;
        }

        private string Diagnosticar(
            string dominante,
            double intensidadeReal,
            double intensidadeSimbolico)
        {
            if (intensidadeReal > 6 && intensidadeSimbolico < 3)
                return "Psicose (Foraclusão)";

            if (dominante == "IMAGINÁRIO")
                return "Neurose Histérica";

            if (dominante == "SIMBÓLICO")
                return "Neurose Obsessiva";

            if (dominante == "REAL")
                return "Estrutura Pulsional";

            return "Estrutura Limítrofe";
        }

        private ResultadoLacaniano ResultadoVazio()
            => new(
                "Indefinida",
                "INDEFINIDO",
                0, 0, 0,
                0, 0, 0
            );
    }
}

