namespace Scriptome.Fingerprint.Classificadores.Psique
{
    public class ClassificadorMBTI : IClassificadorIndividual
    {
        public string Nome => "MBTI-RSI";

        public void Classificar(PerfilPersonagem p, Etograma e)
        {
            // CORREÇÃO: Se não há massa crítica de dados, não chutamos INTJ
            if (p.ScoreDominancia == 0 && p.ScoreAfeto == 0 && p.ScoreEgo == 0)
            {
                e.TipoMbti = "XXXX";
                return;
            }

            // MANTIDO: Sua lógica de Diferenças Relativas
            string IE = RSI(p.ScoreAfeto + p.ScoreDominancia, p.ScoreEgo) > 0 ? "E" : "I";
            string SN = RSI(p.ScoreSensorium, p.ScoreErudicao) > 0 ? "S" : "N";
            string TF = RSI(p.ScoreRacionalidade, p.ScoreAfeto) > 0 ? "T" : "F";
            string JP = RSI(p.ScoreVolicao, p.ScoreIronia) > 0 ? "J" : "P";

            e.TipoMbti = $"{IE}{SN}{TF}{JP}";
        }

        private double RSI(double a, double b)
        {
            double denom = Math.Abs(a) + Math.Abs(b);
            if (denom < 0.0001) return 0;
            return (a - b) / denom;
        }
    }
