        public ClassificadorMBTIV2(IMotorSplicing splicing)
        {
            _splicing = splicing
                ?? throw new ArgumentNullException(nameof(splicing));
        }

        // ===============================
        // INDIVIDUAL
        // ===============================
        public ResultadoMBTI Classificar(RnaBruto rna)
        {
            if (rna == null)
                return new ResultadoMBTI("XXXX");

            var splice = _splicing.Extrair(
                rna,
                "D", "E", "R", "I", "V", "A", "S", "IE");

            double D = splice.Get("D");
            double E = splice.Get("E");
            double R = splice.Get("R");
            double I = splice.Get("I");
            double V = splice.Get("V");
            double A = splice.Get("A");
            double S = splice.Get("S");
            double IE = splice.Get("IE");

            if (D == 0 && A == 0 && E == 0)
                return new ResultadoMBTI("XXXX");

            double scoreEI = RSI(A + D, E);
            double scoreSN = RSI(S, IE);
            double scoreTF = RSI(R, A);
            double scoreJP = RSI(V, I);

            string tipo =
                $"{(scoreEI > 0 ? "E" : "I")}" +
                $"{(scoreSN > 0 ? "S" : "N")}" +
                $"{(scoreTF > 0 ? "T" : "F")}" +
                $"{(scoreJP > 0 ? "J" : "P")}";

            return new ResultadoMBTI(
                Tipo: tipo,
                ScoreEI: scoreEI,
                ScoreSN: scoreSN,
                ScoreTF: scoreTF,
