    /// <summary>
    /// EXPRESSÃO VETORIAL PURA.
    ///
    /// Representa a posição do personagem no espaço etogramático 3D
    /// derivado do DERIVA.
    ///
    /// X → Egoísmo × Altruísmo
    /// Y → Impulso (Id) × Norma (Superego)
    /// Z → Concreto × Abstrato
    ///
    /// Não realiza classificação.
    /// Não possui centroides.
    /// Não determina arquétipos.
    ///
    /// É uma representação geométrica do fenótipo comportamental.
    /// </summary>
    public sealed record ExpressaoVetorial
    (
        double EgoismoAltruismo,
        double ImpulsoNorma,
        double ConcretoAbstrato
    )
    {
        /// <summary>
        /// Calcula a distância euclidiana até outro vetor.
        /// Pode ser utilizada futuramente para clustering
        /// ou análises comparativas.
        /// </summary>
        public double Distancia(ExpressaoVetorial outro)
        {
            return System.Math.Sqrt(
                System.Math.Pow(EgoismoAltruismo - outro.EgoismoAltruismo, 2) +
                System.Math.Pow(ImpulsoNorma - outro.ImpulsoNorma, 2) +
                System.Math.Pow(ConcretoAbstrato - outro.ConcretoAbstrato, 2)
            );
        }
    }
}

