namespace Scriptome.Nucleo.Modelos.Genoma
{
    public sealed class ResultadoSplice
    {
        private readonly Dictionary<string, double> _dados;

        public ResultadoSplice(Dictionary<string, double> dados)
        {
            _dados = dados;
        }

