    /// Não contém interpretação.
    /// Não contém heurística.
    /// É o contrato universal entre DerivaCore e Fingerprint.
    /// </summary>
    public sealed class RnaBruto
    {
        // === Espaço Vetorial Fixo ===
        public double D { get; }
        public double E { get; }
        public double R { get; }
        public double I { get; }
        public double V { get; }
        public double A { get; }
        public double IE { get; }
        public double S { get; }

        // === Área de Expansão ===
        public IReadOnlyDictionary<string, double> Extras { get; }

        public RnaBruto(ResultadoDeriva deriva)
        {
            D = deriva.D;
            E = deriva.E;
            R = deriva.R;
            I = deriva.I;
            V = deriva.V;
            A = deriva.A;
            IE = deriva.IE;
            S = deriva.S;

            Extras = new Dictionary<string, double>(deriva.Extras);
        }
    }
}

namespace Scriptome.Nucleo.Modelos.Genoma
{
    /// <summary>
    /// RNA CARTESIANO
    /// ---------------
    /// Representa a projeção 3D do espaço DERIVA.
    /// Puramente matemático.
    /// </summary>
    public sealed class RnaCartesiano
    {
        public double X { get; }
        public double Y { get; }
        public double Z { get; }

        public RnaCartesiano(RnaBruto rna)
        {
            // Exemplo padrão (substituir se já houver lógica oficial)
            X = rna.D - rna.A;
            Y = rna.R - rna.I;
            Z = rna.V - rna.E;
        }
    }
