using System.Collections.Generic;
using System.IO;
using System.Linq;

namespace Scriptome.Exportacao.Excel.Abas
{
    public class AbaDashboard : IAbaExcel
    {
        public string NomeAba => "Dashboard";
        public int Ordem => 0;

        public void Renderizar(object worksheet, EstatisticasRoteiro dados, string caminhoBase)
        {
            var sheet = (IXLWorksheet)worksheet;

            // 1. CABEÇALHO
            sheet.Cell("B2").Value = "RELATÓRIO DE DNA SCRIPTOME";
            sheet.Cell("B2").Style.Font.FontSize = 20;
            sheet.Cell("B2").Style.Font.Bold = true;
            sheet.Cell("B2").Style.Font.FontColor = XLColor.FromHtml("#1C2833");

            // 2. RESUMO
            sheet.Cell("B4").Value = "RESUMO DO PROJETO";
            sheet.Cell("B4").Style.Font.Bold = true;
            sheet.Cell("B4").Style.Fill.BackgroundColor = XLColor.LightGray;

            PreencherLinhaResumo(sheet, 5, "Duração Estimada:", $"{dados.EstimativaMinutos:F0} min");
            PreencherLinhaResumo(sheet, 6, "Total de Cenas:", dados.TotalCenas);
            PreencherLinhaResumo(sheet, 7, "Dramatismo Global:", dados.MediaDramatismoGlobal.ToString("F2"));
            PreencherLinhaResumo(sheet, 8, "Veredito Emocional:", dados.VereditoEmocionalGlobal);

            // 3. DNA NARRATIVO (TABELA)
            int rowStart = 11;
            sheet.Cell(rowStart, 2).Value = "DNA NARRATIVO";
            sheet.Cell(rowStart, 2).Style.Font.Bold = true;
            sheet.Cell(rowStart, 2).Style.Fill.BackgroundColor = XLColor.LightGray;

            rowStart++;
            sheet.Cell(rowStart, 2).Value = "EIXO";
            sheet.Cell(rowStart, 3).Value = "SCORE";
            sheet.Cell(rowStart, 4).Value = "CRITÉRIO DE ANÁLISE";

            var rangeHeader = sheet.Range(rowStart, 2, rowStart, 4);
            rangeHeader.Style.Font.Bold = true;
            rangeHeader.Style.Font.FontColor = XLColor.White;
            rangeHeader.Style.Fill.BackgroundColor = XLColor.FromHtml("#1C2833");

            var eixos = new List<(string Chave, string Nome, string Desc)>
            {
                ("RITMO", "RITMO", "Velocidade de troca de diálogos e agilidade das frases (Burst)."),
                ("IMPACTO", "IMPACTO", "Intensidade emocional e carga dramática da cena (L)."),
                ("CONFLITO", "CONFLITO", "Nível de atrito direto, oposição e tensão entre personagens."),
                ("COMPLEXIDADE", "COMPLEXIDADE", "Riqueza de vocabulário, densidade intelectual e subtexto."),
                ("DIALOGO", "DIÁLOGO", "Qualidade e naturalidade das falas."),
                ("ATMOSFERA", "ATMOSFERA", "Uso de elementos sensoriais (Sons, Cores, Texturas - Sensorium)."),
                ("VISUALIDADE", "VISUALIDADE", "Proporção 'Show Don't Tell' (Ação vs. Diálogo)."),
                ("DINAMICA", "DINÂMICA", "Variabilidade de batidas e fluxo narrativo.")
            };

            int currentRow = rowStart + 1;
            foreach (var eixo in eixos)
            {
                sheet.Cell(currentRow, 2).Value = eixo.Nome;
                double score = dados.DnaGlobal.ContainsKey(eixo.Chave) ? dados.DnaGlobal[eixo.Chave] : 0.0;

                var cellScore = sheet.Cell(currentRow, 3);
                cellScore.Value = score;
                cellScore.Style.Alignment.Horizontal = XLAlignmentHorizontalValues.Center;

                if (score > 7.0) cellScore.Style.Font.FontColor = XLColor.Green;
                else if (score < 4.0) cellScore.Style.Font.FontColor = XLColor.Red;

                sheet.Cell(currentRow, 4).Value = eixo.Desc;
                currentRow++;
            }

            // ==========================================
            // 4. INSERÇÃO DA IMAGEM (CORREÇÃO)
            // ==========================================
            // Procura por DNA_Octogon.png ou similar na pasta de saída
            string[] possiveisNomes = { "_arco.png", "Arco_Dramatico.png", "DNA_Visual.png" };
            string caminhoImagem = null;

            if (Directory.Exists(caminhoBase))
            {
                foreach (var nome in possiveisNomes)
                {
                    var teste = Path.Combine(caminhoBase, nome);
                    if (File.Exists(teste))
                    {
                        caminhoImagem = teste;
                        break;
                    }
                }
            }

            if (caminhoImagem != null)
            {
                try
                {
                    // Insere a imagem ao lado da tabela (Coluna F)
                    var picture = sheet.AddPicture(caminhoImagem)
                        .MoveTo(sheet.Cell(5, 6)) // F5
                        .Scale(0.8); // Ajuste de escala conforme necessário
                }
                catch
                {
                    sheet.Cell(5, 6).Value = "[Erro ao carregar imagem]";
                }
            }
            else
            {
                sheet.Cell(5, 6).Value = "[Gráfico Visual não encontrado]";
                sheet.Cell(5, 6).Style.Font.Italic = true;
                sheet.Cell(5, 6).Style.Font.FontColor = XLColor.Gray;
            }

            sheet.Columns().AdjustToContents();
        }

        private void PreencherLinhaResumo(IXLWorksheet sheet, int row, string label, object valor)
        {
            sheet.Cell(row, 2).Value = label;
            sheet.Cell(row, 2).Style.Font.Bold = true;
            sheet.Cell(row, 3).Value = valor?.ToString() ?? "-";
        }
    }
}

