                double paginaInicio = 1.0 + (segundosAcumulados / 60.0);

                sheet.Cell(row, 1).Value = cena.Id;
                sheet.Cell(row, 2).Value = cena.Nome;
                sheet.Cell(row, 3).Value = cena.Horario;
                sheet.Cell(row, 4).Value = Math.Round(paginaInicio, 1);
                sheet.Cell(row, 5).Value = cena.DuracaoSegundos;

                var cellDrama = sheet.Cell(row, 6);
                cellDrama.Value = cena.DramatismoTotal;
                if (cena.DramatismoTotal > 8) cellDrama.Style.Font.FontColor = XLColor.Red;

                sheet.Cell(row, 7).Value = cena.BurstScore;
                sheet.Cell(row, 8).Value = cena.PacingScore;
                sheet.Cell(row, 9).Value = cena.VereditoEmocional;
                sheet.Cell(row, 10).Value = cena.EstiloCena;
                sheet.Cell(row, 11).Value = string.Join(", ", cena.AssinaturaEmocional);

                segundosAcumulados += cena.DuracaoSegundos;
                row++;
            }

            sheet.Columns().AdjustToContents();
            sheet.Column(11).Width = 50;
            sheet.SheetView.FreezeRows(1);
        }
    }
}

using ClosedXML.Excel;
using Scriptome.Infrastructure.Interfaces;
using Scriptome.Nucleo.Modelos;
using Scriptome.Nucleo.Modelos.Analise;
using System.Linq;

namespace Scriptome.Exportacao.Excel.Abas
{
    public class AbaMatrizSocial : IAbaExcel
    {
        public string NomeAba => "Matriz Social";
        public int Ordem => 30;

        public void Renderizar(object worksheet, EstatisticasRoteiro dados, string caminhoBase)
        {
            var sheet = (IXLWorksheet)worksheet;
            var interacoes = dados.MatrizInteracoes;

            if (interacoes == null || !interacoes.Any())
            {
                sheet.Cell("B2").Value = "Nenhuma interação detectada.";
                return;
            }

            var personagens = interacoes.Select(i => i.PersonagemA)
                .Union(interacoes.Select(i => i.PersonagemB))
                .Distinct()
                .OrderBy(p => p)
                .ToList();

            for (int i = 0; i < personagens.Count; i++)
            {
                sheet.Cell(i + 2, 1).Value = personagens[i];
                sheet.Cell(i + 2, 1).Style.Font.Bold = true;
                sheet.Cell(1, i + 2).Value = personagens[i];
                sheet.Cell(1, i + 2).Style.Font.Bold = true;
                sheet.Cell(1, i + 2).Style.Alignment.TextRotation = 90;
            }

            foreach (var interacao in interacoes)
            {
                int indexA = personagens.IndexOf(interacao.PersonagemA);
                int indexB = personagens.IndexOf(interacao.PersonagemB);

                if (indexA >= 0 && indexB >= 0)
                {
                    int linha = indexA + 2;
                    int coluna = indexB + 2;
                    int valor = interacao.Peso;

                    sheet.Cell(linha, coluna).Value = valor;
                    sheet.Cell(coluna, linha).Value = valor;

                    if (valor > 20) { sheet.Cell(linha, coluna).Style.Fill.BackgroundColor = XLColor.DarkBlue; sheet.Cell(linha, coluna).Style.Font.FontColor = XLColor.White; }
                    else if (valor > 10) { sheet.Cell(linha, coluna).Style.Fill.BackgroundColor = XLColor.CornflowerBlue; sheet.Cell(linha, coluna).Style.Font.FontColor = XLColor.White; }
                    else if (valor > 0) { sheet.Cell(linha, coluna).Style.Fill.BackgroundColor = XLColor.LightBlue; }

                    if (linha != coluna) // Copia estilo simétrico
                    {
                        sheet.Cell(coluna, linha).Style = sheet.Cell(linha, coluna).Style;
                    }
                }
            }
            sheet.Columns().AdjustToContents();
            sheet.Column(1).Width = 20;
        }
    }
}

using ClosedXML.Excel;
using Scriptome.Fingerprint;
using Scriptome.Infrastructure.Interfaces;
using Scriptome.Nucleo.Modelos;
using Scriptome.Nucleo.Modelos.Analise;
using System;

namespace Scriptome.Exportacao.Excel.Abas
{
    public class AbaTaxonomia : IAbaExcel
    {
        public string NomeAba => "Taxonomia";
        public int Ordem => 40;

        public void Renderizar(object worksheet, EstatisticasRoteiro dados, string caminhoBase)
        {
            var sheet = (IXLWorksheet)worksheet;

            try
            {
                var motorTaxo = new MotorTaxonomia();
                string arvoreTexto = motorTaxo.GerarArvoreFilogenetica(dados.Fenotipos.ToList());

                var celula = sheet.Cell(1, 1);
                celula.Value = arvoreTexto;
                celula.Style.Font.FontName = "Consolas";
                celula.Style.Alignment.WrapText = true;

                sheet.Column(1).Width = 100;
                sheet.Row(1).Height = 400;
            }
            catch (Exception ex)
            {
                sheet.Cell(1, 1).Value = $"Erro ao gerar taxonomia: {ex.Message}";
                sheet.Cell(1, 1).Style.Font.FontColor = XLColor.Red;
            }
        }
    }
}
